// src/lib/apidoc.ts — ⚠ 自動產生，不要手改！原稿是專案根目錄 API.md。
// 改文件流程：編輯 API.md → node tools/build-apidoc.mjs → npx wrangler deploy
export const APIDOC: string = "網頁後台能做的每一件事，這裡都有對應的 HTTP API — 用 curl、排程或 AI agent 都能操作整個網站。\n\n## 1. 開始之前\n\n| 項目 | 值 |\n|---|---|\n| 正式站 | `https://uaip.cc.cd`（Cloudflare Workers） |\n| 本機開發 | `http://localhost:8787`（`npx wrangler dev`） |\n| 回應格式 | 一律 JSON（UTF-8） |\n| 時間欄位 | 一律 UTC 的 ISO 8601（例 `2026-07-09T03:00:00.000Z`），顯示時自行轉時區 |\n\n**三種身分**：\n\n1. **公開**：免驗證（whoami、已發佈內容、選單、站名）。\n2. **管理員**：路徑含 `/admin` 的、以及 `/api/logs`。兩種通過方式（擇一）：\n   - 請求標頭 `Authorization: Bearer <管理金鑰>`（curl／排程／AI agent 用）。管理金鑰＝Cloudflare Workers secret **LOGS_TOKEN**，跟 /logs、/admin 網頁登入同一把；值記在 ADMIN.md（不會上網）。\n   - 管理員 Google 帳號的登入 cookie（瀏覽器用）：管理員信箱登入後，管理頁與管理員 API 免金鑰。管理員信箱＝環境變數 **ADMIN_EMAILS**（逗號分隔，例 `admin@example.com`；沒設定＝沒有信箱直升管理員，只認資料庫 users.is_admin）。\n   - **本機開發（localhost）免金鑰**；正式站沒帶或帶錯一律回 401。用 cookie 身分時，跨網站送出的請求會被 Origin 檢查擋掉（防 CSRF）。\n   - 換金鑰：`printf '新金鑰' | npx wrangler secret put LOGS_TOKEN`，設定後立即生效（Workers secret 不需重新部署）。\n3. **會員**：任何人用 Google 登入即為會員（見 `/auth/login`）。會員功能（API 中轉、VPN 訂閱）要**管理員核准**（status=approved）後才生效。\n   - 網頁操作靠登入 cookie；**API 中轉**另用會員自己的金鑰 `uak-…`（在 /relay 頁產生，帶法同各家 AI API）。\n\n### 30 秒上手：發一篇新聞\n\n```bat\n:: 1) 文章存成「UTF-8 編碼」的 art.json（中文寫在指令列會變亂碼，一定要走檔案）：\n::    { \"category\":\"news\", \"status\":\"published\", \"title\":\"標題\",\n::      \"summary\":\"一兩句摘要\", \"cover\":\"/img/5\", \"body_md\":\"內文 **Markdown**\" }\n:: 2) 送出（Windows cmd 換行符是 ^；Linux/macOS 改用 \\）：\ncurl -X POST https://uaip.cc.cd/api/admin/articles ^\n  -H \"Authorization: Bearer 管理金鑰\" ^\n  -H \"content-type: application/json; charset=utf-8\" ^\n  --data-binary @art.json\n```\n\n回 `{ \"id\": 12, \"status\": \"published\" }` → 文章立即上線在 `/news/12`。\n\n## 2. 端點總覽\n\n### 公開（免金鑰）\n\n| 方法與路徑 | 用途 |\n|---|---|\n| `GET /api/whoami` | 訪客自己的連線資訊（IP、UA、地理位置） |\n| `GET /api/articles` | 已發佈文章列表（分頁、可篩分類） |\n| `GET /api/articles/{id}` | 單篇已發佈文章（含 Markdown 原稿） |\n| `GET /api/pages` | 已發佈自訂頁面列表 |\n| `GET /api/pages/{slug}` | 單一已發佈自訂頁面 |\n| `GET /api/menu` | 側邊欄選單 |\n| `GET /api/settings` | 網站公開設定（站名、Playground 是否全員開放、聯絡連結） |\n| `GET /api/health` | 健康檢查 `{ ok, version, db }`（部署後 smoke 測試用） |\n| `POST /api/csp-report` | CSP 違規回報收集端（瀏覽器自動送；10% 取樣進錯誤日誌；永遠 204） |\n| `GET /img/{id}` | 圖片（D1 讀出、邊緣快取一年） |\n| `GET /feed` | RSS 訂閱源（最新 20 篇） |\n| `GET /sitemap` | 搜尋引擎網址清單（含文章與自訂頁面） |\n\n### 會員（要登入 cookie）\n\n| 方法與路徑 | 用途 |\n|---|---|\n| `GET /api/me` | 我是誰（登入狀態、被批准的服務清單 `services`、是否管理員；未登入回 `{user:null}`） |\n| `POST /api/account/key` | 產生／重生自己的中轉金鑰 `uak-…`（明文只回一次） |\n| `DELETE /api/account/key` | 撤銷自己的中轉金鑰 |\n| `POST /api/account/vpn-token` | 重生自己的 VPN 訂閱代碼（舊訂閱網址立即失效） |\n| `GET /api/relay/channels` | 目前可用的中轉管道清單（含各管道的模型名稱 `models`；不含金鑰） |\n| `GET /api/playground/models` | Playground 可選的模型清單（依渠道分組；要有 playground 服務） |\n| `POST /api/playground/chat` | Playground 聊天（SSE 串流；要有 playground 服務，見 §5f） |\n| `GET /api/playground/conversations` | 自己的 Playground 對話列表 |\n| `GET/PUT/DELETE /api/playground/conversations/{id}` | 讀取訊息／改名／刪除自己的對話 |\n\n### 會員服務端點（不同驗證）\n\n| 方法與路徑 | 驗證 | 用途 |\n|---|---|---|\n| `ANY /relay/{管道}/{上游路徑…}` | 會員金鑰 `uak-…` | API 中轉：轉發到上游、串流直通（見 §6） |\n| `GET /vpn/sub/{token}` | 訂閱 token 本身 | VPN 訂閱鏡像：給 Clash／v2rayN 直接訂閱（見 §7） |\n| `GET /auth/login?next=…` | — | 導向 Google 登入（localhost 提供測試登入表單） |\n| `POST /auth/logout` | 登入 cookie | 登出 |\n\n### 管理員（要金鑰）\n\n| 方法與路徑 | 用途 |\n|---|---|\n| `GET /api/admin/articles` | 全部文章（**含草稿**，依更新時間排序，最多 500 筆） |\n| `POST /api/admin/articles` | 新增文章 |\n| `GET /api/admin/articles/{id}` | 讀單篇（含草稿、含原稿） |\n| `PUT /api/admin/articles/{id}` | 更新文章（**整包覆蓋**） |\n| `DELETE /api/admin/articles/{id}` | 刪除文章（不可復原） |\n| `GET /api/admin/pages` | 全部自訂頁面（**含草稿**） |\n| `POST /api/admin/pages` | **新增自訂頁面（開新連結就靠這支）** |\n| `GET /api/admin/pages/{id或slug}` | 讀單頁（含草稿、含原稿） |\n| `PUT /api/admin/pages/{id或slug}` | 更新頁面（**整包覆蓋**，可改 slug） |\n| `DELETE /api/admin/pages/{id或slug}` | 刪除頁面（不可復原） |\n| `POST /api/admin/media` | 上傳圖片 |\n| `PUT /api/admin/menu` | 覆蓋側邊欄選單 |\n| `GET /api/admin/settings` | 目前存的網站設定原況（給 /settings 管理頁當編輯初值；數字鍵沒設過回 `null`，另附 `defaults`） |\n| `PUT /api/admin/settings` | 改網站設定（站名、Playground 全員開放、配額全域預設、計量開關） |\n| `GET /api/logs` | 訪客紀錄查詢 |\n| `GET /api/admin/errors` | 站內錯誤日誌（`?limit&offset&src`；relay/playground/OAuth/CSP 埋點） |\n| `DELETE /api/admin/errors` | 清空錯誤日誌 |\n| `GET /api/admin/stats` | 用量統計（`?days=7`；每日×服務、渠道×模型、每人彙總、原始耗時值供算 p95、估算成本）— /logs 用量分頁的數據源 |\n| `GET /api/admin/conversations` | 全站 Playground 對話總表（`?limit&offset&q&user_id`；新→舊，帶會員信箱）— /logs 總對話紀錄分頁的數據源 |\n| `GET /api/admin/conversations/{id}` | 讀任一會員的單則對話（含全部訊息） |\n| `GET /api/admin/prices` | 模型定價表（成本記帳用） |\n| `PUT /api/admin/prices` | 覆蓋模型定價表（**整包覆蓋**；pattern 尾端 `*`＝前綴匹配） |\n| `GET /api/admin/apidoc` | 這份文件的 Markdown 原稿（`{ md }`） |\n| `GET /api/admin/users` | 全部會員（狀態、已批准服務、用量、最後登入） |\n| `PUT /api/admin/users/{id}` | 批准／封鎖／升降管理員／分服務批准（`{ action }`，見 §5c） |\n| `DELETE /api/admin/users/{id}` | 刪除會員 |\n| `GET /api/admin/relay/channels` | 全部中轉管道（上游金鑰遮罩） |\n| `POST /api/admin/relay/channels` | 新增中轉管道 |\n| `PUT /api/admin/relay/channels/{id}` | 更新管道（整包覆蓋；沒帶 api_key＝保留舊金鑰） |\n| `DELETE /api/admin/relay/channels/{id}` | 刪除管道 |\n| `GET /api/admin/vpn/channels` | 全部 VPN 渠道（上游訂閱網址遮罩） |\n| `POST /api/admin/vpn/channels` | 新增 VPN 渠道（機場訂閱或手動節點） |\n| `PUT /api/admin/vpn/channels/{id}` | 更新渠道（整包覆蓋；沒帶 url＝保留舊網址） |\n| `DELETE /api/admin/vpn/channels/{id}` | 刪除渠道 |\n\n## 3. 三條鐵則（先讀這個再動手）\n\n1. **PUT 是整包覆蓋**（文章、頁面、選單都是）：先 GET 拿舊資料 → 改要改的欄位 → 整包 PUT 回去。沒帶的欄位會被清空。\n2. **圖片編號永遠不能重複使用**：`/img/{id}` 掛一年 immutable 邊緣快取，而 uaip.cc.cd 的快取清除權在 cc.cd 網域主手上、我們清不掉。刪過的編號作廢；換圖＝上傳拿新編號＋更新文章裡的網址。也**不要**重設 media 表的流水號。\n3. **中文內容一定走 UTF-8 檔案**：curl 用 `--data-binary @檔案` 傳送；把中文直接寫在 Windows 指令列會變亂碼（實測踩過）。\n\n## 4. 公開 API 詳細\n\n### GET /api/whoami\n\n回傳由 Cloudflare 邊緣節點觀測到的請求資訊。欄位：`ip`、`ua`、`lang`、`country`、`city`、`region`、`region_code`、`postal`、`latitude`、`longitude`、`timezone`、`asn`、`isp`、`colo`、`http`、`tls`。\n\n### GET /api/articles — 已發佈文章列表\n\n| 參數 | 說明 |\n|---|---|\n| `category` | `news` 或 `article`；省略＝全部 |\n| `p` | 頁碼，預設 1 |\n| `per` | 每頁筆數 1–50，預設 10 |\n\n回 `{ rows, total, page, per, pages }`；rows 每筆含 `id`、`category`、`title`、`summary`、`cover`、`views`、`published_at`，依發佈時間新到舊。草稿一律看不到；用 API 讀**不會**增加瀏覽數（views 只算真人看文章頁）。\n\n### GET /api/articles/{id} — 單篇已發佈文章\n\n回 `{ row }`，含 `body_md`（Markdown 原稿）。加 **`?html=1`** 多回 `body_html`（伺服器轉好的 HTML，跟正式文章頁同設定）。找不到或還是草稿 → 404。\n\n### GET /api/pages — 已發佈自訂頁面列表\n\n回 `{ rows }`，每筆含 `slug`、`title`、`summary`、`updated_at`。每頁的公開網址＝ **`/p/{slug}`**（例 slug=about → `https://uaip.cc.cd/p/about`）。\n\n### GET /api/pages/{slug} — 單一已發佈自訂頁面\n\n回 `{ row }`，含 `body_md`。加 **`?html=1`** 多回 `body_html`。找不到或還是草稿 → 404。\n\n### GET /api/menu — 側邊欄選單\n\n回 `{ items, custom }`。items 是「由上到下」的平面陣列，每項：\n\n| 欄位 | 說明 |\n|---|---|\n| `kind` | `section`（分類標題）或 `link`（連結） |\n| `label` | 中文名稱 |\n| `label_en` | 英文名稱（空字串＝英文介面也顯示中文） |\n| `url` | 連結網址（section 為空字串） |\n\n`custom:false` 表示還沒自訂過，回的是內建預設選單。\n\n### GET /api/settings — 網站公開設定\n\n回 `{ brand, custom, pg_open, contact_url, demo }`。brand＝站名（用在分頁標題、og:site_name、JSON-LD、RSS 頻道名）；`custom:false` 表示用內建預設（＝正式網址主機名）。`pg_open`＝Playground 是否對所有登入會員開放（見 §5 的網站設定）。`contact_url`＝管理員聯絡連結（會員頁登入閘門的「聯絡我」鈕；空字串＝沒設定、前端不顯示該鈕）。`demo`＝Playground 體驗模式是否開放匿名試聊（布林；渠道與額度細節不公開）。\n\n## 5. 管理員 API 詳細\n\n### 文章：/api/admin/articles\n\nPOST（新增）與 PUT（更新）共用同一組 JSON 欄位：\n\n| 欄位 | 規則 |\n|---|---|\n| `category` | `news`（新聞）或 `article`（文章）；預設 news |\n| `status` | `draft`（草稿）或 `published`（發佈）；預設 draft |\n| `title` | **必填**，最長 200 字 |\n| `summary` | 最長 500 字 — 列表兩行摘要，也是搜尋結果與分享卡描述 |\n| `cover` | 縮圖網址，最長 300 字（通常是 `/img/{id}`，也可貼外部網址） |\n| `body_md` | 內文 Markdown，最長 200KB（空一行分段、`## 小標`、`**粗體**`、`[文字](網址)`、插圖 `![說明](/img/{id})`；breaks 模式：按一次 Enter 就是換行） |\n\n- POST 回 `{ id, status }`；PUT 回 `{ id, status }`；DELETE 回 `{ ok:true }`。\n- `published_at` 在**第一次發佈**時寫入，之後再編輯、轉草稿再發佈都不變（列表排序穩定）。\n- 文章上線網址：`/news/{id}` 或 `/articles/{id}`（依 category）。\n\n### 自訂頁面：/api/admin/pages — 用 API 開新連結\n\n新增一個頁面＝網站多一個公開網址 **`/p/{slug}`**。適合「關於本站」「隱私權政策」「聯絡方式」這類獨立頁。\n\nPOST 與 PUT 共用欄位：\n\n| 欄位 | 規則 |\n|---|---|\n| `slug` | **必填** — 網址代稱：小寫英數與連字號（頭尾不能是連字號），最長 64 字。例 `about`、`privacy-policy` |\n| `title` | **必填**，最長 200 字（頁面大標＋分頁標題） |\n| `status` | `draft`（草稿）或 `published`（發佈）；預設 draft。**草稿對外看不到** |\n| `summary` | 最長 500 字 — meta description（SEO 與分享卡描述） |\n| `body_md` | 內文 Markdown，最長 200KB（規則同文章） |\n\n- POST 回 `{ id, slug, status, url }`；slug 已被用回 **409 `{ error:\"slug-taken\" }`**。\n- 單頁路由 `/{id或slug}`：純數字當編號、其他當 slug，兩種都可以（agent 用 slug 比較直覺）。\n- PUT 可以改 slug（頁面搬新網址，舊網址會變 404 — 已被收錄或被連結的頁面不建議改）。\n- 發佈後自動進 `/sitemap`；**不會**自動出現在側邊欄 — 要掛選單就再 `PUT /api/admin/menu` 加一條 url 為 `/p/{slug}` 的連結（見下）。\n\n建立並發佈一個「關於本站」頁：\n\n```bat\n:: page.json（UTF-8）：\n::   { \"slug\":\"about\", \"status\":\"published\", \"title\":\"關於本站\",\n::     \"summary\":\"這個網站是誰、在做什麼。\", \"body_md\":\"## 哈囉\\n\\n這裡是……\" }\ncurl -X POST https://uaip.cc.cd/api/admin/pages ^\n  -H \"Authorization: Bearer 管理金鑰\" ^\n  -H \"content-type: application/json; charset=utf-8\" --data-binary @page.json\n:: 回 { \"id\":1, \"slug\":\"about\", \"status\":\"published\", \"url\":\"/p/about\" }\n```\n\n### 圖片：POST /api/admin/media\n\n- 請求本體＝圖片**二進位**（不是表單、不是 base64），Content-Type 帶 `image/webp`、`image/jpeg`、`image/png` 或 `image/gif`。\n- 大小上限 **1.8MB**（D1 單值限 2MB）。走 API 上傳**不會自動壓縮**，請先自己縮好（建議最寬 1400–1600px、JPEG 品質 85 左右）；網頁後台上傳才有自動壓縮。\n- 可選參數 `?w=寬&h=高`（記尺寸，後台顯示用）。\n- 回 `{ id, url, bytes, w, h }`，url 形如 `/img/9` — 填進文章 cover，或以 `![說明](/img/9)` 插進內文。\n\n```bat\ncurl -X POST \"https://uaip.cc.cd/api/admin/media?w=1400&h=788\" ^\n  -H \"Authorization: Bearer 管理金鑰\" ^\n  -H \"content-type: image/jpeg\" --data-binary @cover.jpg\n```\n\n### 選單：PUT /api/admin/menu\n\n本體 `{ \"items\": [ … ] }`，格式同 GET /api/menu 的 items；整份選單照陣列順序**覆蓋**寫入。\n\n- 每項規則：`label` 必填最長 60 字；`label_en` 選填最長 60 字；link 的 `url` 必填最長 300 字，**必須以 `/` 或 `http://` 或 `https://` 開頭**；最多 60 項。\n- 傳 **`{ \"items\": [] }`（空陣列）＝清掉自訂選單＝還原內建預設**。\n- 回 `{ ok, count, custom }`。\n- 側邊欄的「管理員區」（管理員設定、訪客紀錄、API 文件）不在選單資料裡 — 那是登入過的裝置由前端動態長出來的，改不到也不用管。\n\n標準流程（先拿現況、改完整包放回）：\n\n```bat\ncurl https://uaip.cc.cd/api/menu > menu.json\n:: 編輯 menu.json，例如 items 尾端加 { \"kind\":\"link\", \"label\":\"關於本站\",\n::   \"label_en\":\"About\", \"url\":\"/p/about\" }，然後：\ncurl -X PUT https://uaip.cc.cd/api/admin/menu ^\n  -H \"Authorization: Bearer 管理金鑰\" ^\n  -H \"content-type: application/json; charset=utf-8\" --data-binary @menu.json\n```\n\n### 網站設定：GET / PUT /api/admin/settings\n\n**GET**（2026-07-17，/settings 管理頁的數據源）回目前**存的**原況：`{ ok, brand, custom, contact_url, pg_open, pg_default_system, relay_meter, quota_relay_day, quota_pg_day, rl_per_min, demo_mode, demo_active, demo_channel, demo_models, demo_per_min, demo_per_ip_day, demo_global_day, demo_max_tokens, tg_chat_id, tg_token_set, tg_token_hint, tg_env_set, tg_active, defaults }` — 數字鍵沒設過回 `null`（不是內建預設值），內建預設放在 `defaults` 物件；`demo_mode` 是開關本身的儲存值、`demo_active` 才是真正生效與否（開關＋`demo_channel` 都要有）；Telegram bot token **絕不回明文**（只回 `tg_token_set` 與尾 4 碼 `tg_token_hint`）。\n\n**PUT：本體帶哪個鍵就改哪個鍵，沒帶的不動**（2026-07-14 起；跟文章／選單的整包覆蓋不同）。回 `{ ok, brand, custom, contact_url, pg_open, pg_default_system, quota_relay_day, quota_pg_day, rl_per_min, relay_meter, demo_* }`（改完的現況；配額鍵沒設過時顯示內建預設）。\n\n| 鍵 | 說明 |\n|---|---|\n| `brand` | 站名，最長 60 字；**傳空字串＝還原內建預設**（＝正式網址主機名）。改完立即生效（分頁標題、og:site_name、JSON-LD、RSS 頻道名；主站首頁的「IP·UA 查詢」標題不受影響） |\n| `contact_url` | 管理員對外聯絡連結（`http(s)://` 開頭，最長 300 字）；顯示在會員頁登入閘門的「聯絡我」鈕。**空字串＝移除＝不顯示聯絡鈕** |\n| `pg_open` | `true`／`false` — **Playground 開放給所有登入會員**：開啟後任何登入會員不用逐一批准就能用 LLM Playground（被封鎖的帳號照樣擋；只影響 playground，relay 與 vpn 照舊看個人批准）。`false`＝回到逐人批准。網頁上在 /members 頁最上方也有這顆開關 |\n| `pg_default_system` | **Playground 的預設系統提示詞**（2026-07-21；最長 4000 字，超過截斷）：所有**沒有自己填** `system_prompt` 的渠道共用這一段 — 改一次等於一次換掉全部渠道，不必逐個開視窗。渠道自己填了就以渠道為準（不疊加）。**空字串＝刪鍵＝還原程式內建的 `PG_DEFAULT_SYSTEM`**；GET 的 `defaults.pg_default_system` 就是那段內建值（網頁上拿它當灰字）。**只作用在 `/playground`**，`/relay` 中轉照樣不注入任何東西。網頁在 /settings 的「Playground 預設系統提示詞」卡 |\n| `quota_relay_day` | 中轉每日請求數的**全域預設**（正整數）；`null` ＝ 回到內建預設 500。個人覆寫（§5c 的 `set_quota`）優先於這個值；**管理員完全不吃配額** |\n| `quota_pg_day` | Playground 每日訊息數的全域預設；`null` ＝ 內建預設 200 |\n| `rl_per_min` | 每分鐘請求數上限（滾動 60 秒、中轉＋Playground 合併計）；`null` ＝ 內建預設 30 |\n| `relay_meter` | `false` ＝ 中轉退回**純直通**（不掃 usage、不寫 req_log）— 計量出怪問題時的免部署保險；`true` ＝ 恢復計量（預設）。平常不要動 |\n| `tg_bot_token` | Telegram 告警的 bot token（2026-07-17 起可存這裡；最長 100 字，**空字串＝刪鍵**）。cron 每 5 分鐘掃 errlog 推播時**這裡優先**、Cloudflare secrets（TG_BOT_TOKEN）後備。回讀一律遮罩（`tg_token_set`／`tg_token_hint`）、audit 不落明文。網頁在 /settings 的「Telegram 告警」卡 |\n| `tg_chat_id` | Telegram 告警的 chat id（最長 50 字，空字串＝刪鍵；同樣 D1 優先、secrets TG_CHAT_ID 後備）。token 與 chat id **都設好**告警才會發送 |\n| `demo_mode` | `true`／`false` — **Playground 體驗模式**（2026-07-17 v2.0.0）：開啟後**未登入訪客**可直接在 /playground 試聊。要同時設好 `demo_channel` 才生效。fail-closed 限流（詳見 ADR-0009）：每 IP 每分鐘／每日＋全站每日三道上限，限流器故障時直接 503 絕不放行 |\n| `demo_channel` | 體驗模式鎖定的渠道 slug（**必設**，沒設＝demo 不生效）；訪客只能用這個渠道 |\n| `demo_models` | 體驗模式的模型白名單（逗號分隔）；空＝該渠道全部模型 |\n| `demo_per_min` | 體驗模式每 IP 每分鐘上限；`null`＝內建預設 3 |\n| `demo_per_ip_day` | 每 IP 每日上限；`null`＝內建預設 10 |\n| `demo_global_day` | **全站**每日上限（燒錢保險）；`null`＝內建預設 200 |\n| `demo_max_tokens` | 強制的回覆 token 上限；`null`＝內建預設 512 |\n\n```bat\ncurl -X PUT https://uaip.cc.cd/api/admin/settings ^\n  -H \"Authorization: Bearer 管理金鑰\" ^\n  -H \"content-type: application/json\" --data-binary \"{\\\"brand\\\":\\\"新站名\\\"}\"\n\n:: Playground 開放給所有登入會員（false＝關閉）：\ncurl -X PUT https://uaip.cc.cd/api/admin/settings ^\n  -H \"Authorization: Bearer 管理金鑰\" ^\n  -H \"content-type: application/json\" --data-binary \"{\\\"pg_open\\\":true}\"\n```\n\n### 模型定價（成本記帳）：/api/admin/prices\n\n成本記帳（2026-07-17 v2.0.0）：req_log 早就記了每次請求的 token 數，這張定價表讓 stats 與 /logs 用量分頁能把 token 換算成**估算**美元成本。定價只影響報告顯示，不影響配額（配額算次數，見 §網站設定）。\n\n- `GET` → `{ items: [ { pattern, input_usd_per_m, output_usd_per_m, note, updated_at }, … ] }`\n- `PUT` 本體 `{ items: [ … ] }`，**整包覆蓋**（跟選單同款：先 GET → 改 → 整包 PUT；空陣列＝清空）。\n\n| 欄位 | 說明 |\n|---|---|\n| `pattern` | 模型名稱；尾端 `*` ＝前綴匹配（例 `gpt-4o*`）。**精確名優先於前綴、前綴取最長**（`gpt-4o-mini*` 贏過 `gpt-4o*`） |\n| `input_usd_per_m` | 每百萬 input tokens 的美元價（≥0） |\n| `output_usd_per_m` | 每百萬 output tokens 的美元價（≥0） |\n| `note` | 備註（例：官網牌價日期），最長 200 字 |\n\n```bat\ncurl -X PUT https://uaip.cc.cd/api/admin/prices ^\n  -H \"Authorization: Bearer 管理金鑰\" ^\n  -H \"content-type: application/json\" ^\n  --data-binary \"{\\\"items\\\":[{\\\"pattern\\\":\\\"gpt-4o*\\\",\\\"input_usd_per_m\\\":2.5,\\\"output_usd_per_m\\\":10}]}\"\n```\n\n沒對上定價的模型在 stats 回應的 `unpriced_models` 陣列與 /logs 用量分頁會被點名提醒。\n\n### 訪客紀錄：GET /api/logs\n\n| 參數 | 說明 |\n|---|---|\n| `limit` | 1–200，預設 50 |\n| `offset` | 分頁位移 |\n| `q` | 模糊搜尋（ip / ua / path / country / city / isp） |\n| `since` | ISO 時間 — 額外回傳該時間之後的瀏覽數與不重複 IP 數（today / todayIps） |\n\n回 `{ rows, total, today?, todayIps? }`。\n\n### 總對話紀錄：/api/admin/conversations\n\n管理視角看**全站會員**在 Playground 存下的對話（2026-07-20 上線）——會員版 `/api/playground/conversations` 只看得到自己的，這兩支不限擁有者。網頁在 **/logs 的「總對話紀錄」分頁**。\n\n`GET /api/admin/conversations`\n\n| 參數 | 說明 |\n|---|---|\n| `limit` | 1–200，預設 50 |\n| `offset` | 分頁位移 |\n| `q` | 模糊搜尋（標題／會員信箱／姓名／模型／渠道；**不搜訊息內容**）。網頁上沒有這個欄位，只給 curl／agent 用 |\n| `user_id` | 只看某個會員的對話 |\n\n回 `{ rows, total }`，`rows` 依 `updated_at` **新→舊**；每列：`id`、`user_id`、`email`、`name`（對話是誰的）、`title`、`channel`、`model`、`msgs`（訊息則數）、`created_at`、`updated_at`。帳號已刪除時 `email`／`name` 是 `null`。\n\n`GET /api/admin/conversations/{id}` → `{ conv, messages }`：`conv` 是那列（額外帶 `email`、`name`），`messages` 依時間**舊→新**（聊天的閱讀順序）、上限 500 則，每則 `id`、`role`、`content`、`model`、`created_at`。找不到回 404。\n\n> 這兩支**唯讀**——管理員這邊不提供刪除，避免誤刪會員資料；會員自己可以在 /playground 刪自己的對話。\n> 體驗模式（未登入試用）的對話**不落資料庫**，所以不會出現在這裡。\n\n## 5b. 會員與帳號 API\n\n- `GET /api/me` → `{ user }`（未登入 `{ user:null }`）。user 含 `email`、`name`、`picture`、`status`（pending/approved/blocked）、`is_admin`、`approved`、`services`（被批准的服務陣列，如 `[\"relay\",\"vpn\",\"playground\"]`；管理員固定是全部）、`has_key`、`key_hint`、`key_at`、`relay_calls`、`usage`（2026-07-14 起：今日用量 `{ relay_today, relay_limit, pg_today, pg_limit }` — 只含有權限的服務、管理員 limit 是 `null`＝無上限、兩服務都沒權限時整塊省略；UTC 午夜重置）。**`vpn_token`／`vpn_pulls` 只有「管理員或被批准 vpn 服務」的人才有**（VPN 隱形：無權限者連鍵都不出現，`/vpn` 頁對他們也回 SPA、選單也不渲染）。\n- `POST /api/account/key` → `{ key, key_hint, key_at }`。**key 明文只在這次回應出現**，資料庫只存 SHA-256；重生會讓舊金鑰立即失效。`DELETE` 撤銷。\n- `POST /api/account/vpn-token` → `{ vpn_token }`。重生訂閱代碼（舊 `/vpn/sub/<舊token>` 立即失效）。\n- `POST /api/account/logout-all`（2026-07-14）→ `{ ok }`。**登出所有裝置**：刪光自己全部 session（含這一把）並清本機 cookie。手機不見／公用電腦忘了登出時用；頭像下拉選單也有這個鈕。\n- 以上都要登入 cookie；跨站請求被 Origin 擋（403 bad-origin）。\n\n## 5c. 成員管理：/api/admin/users（分服務批准）\n\n2026-07-13 起改**分服務批准**：三個服務 `relay`（API 中轉站）、`vpn`、`playground`（LLM Playground）可以分別開關，存在 `users.services`（逗號分隔）。管理員帳號不看清單、全部服務都能用。\n\n> `playground` 另有**全站開關**（`PUT /api/admin/settings` 的 `pg_open`，見 §5）：開啟時所有登入會員都能用 Playground、不看個人批准（`/api/me` 的 `services` 也會多出 playground）；關閉才回到這裡的逐人批准。relay 與 vpn 沒有全站開關。\n\n- `GET` → `{ rows }`：每筆 `id`、`email`、`name`、`picture`、`status`、`services`（逗號分隔字串）、`is_admin`、`relay_calls`、`vpn_pulls`、`last_login`、`created_at`、配額覆寫欄（`quota_relay_day`、`quota_pg_day`、`rl_per_min`；`null`＝用全域）、今日用量（`relay_today`、`pg_today`，UTC 日窗）；排序 pending 在前。\n- `PUT /api/admin/users/{id}` 本體三選一：\n  - `{ \"action\": \"approve\" | \"block\" | \"unblock\" | \"make_admin\" | \"drop_admin\" }` — `approve` 是快速鍵＝**一次批准全部服務**；`unblock` 恢復原本的服務清單（清單是空的就退回 pending）。封鎖會同時把該會員踢下線（刪其 session）。\n  - `{ \"action\": \"set_services\", \"services\": [\"relay\",\"vpn\"] }` — **整包覆蓋**服務清單（只收合法服務名）。給了任何服務＝status 變 approved；全部收回＝退回 pending；封鎖中的帳號只改清單、狀態不動。\n  - `{ \"action\": \"set_quota\", \"quota_relay_day\": 100, \"quota_pg_day\": null, \"rl_per_min\": 10 }` — **個人配額覆寫**（2026-07-14）：帶哪鍵改哪鍵；值收 0 以上整數（0＝直接關掉該服務的額度）或 `null`＝清掉覆寫、回到全域預設（§5 的網站設定）。管理員帳號不吃配額，設了也沒作用。網頁上在 /members 每個會員的「配額」鈕（有自訂會多顯示 `*`）\n  - `{ \"action\": \"revoke_sessions\" }` —（2026-07-14）撤銷該會員**所有裝置**的登入狀態（session 全刪；帳號狀態與服務不動）。懷疑帳號被冒用時先用這個。\n- 所有變更（users／settings／channels／menu／articles／pages／media）都會寫 **audit_log**（誰、何時、對誰、做了什麼；summary 絕不含金鑰或上游網址本體）。\n- `DELETE /api/admin/users/{id}` 刪除帳號。\n- **護欄**：不能封鎖／降級／刪除自己；也不能動到 ADMIN_EMAILS 指定的管理員帳號（回 403 protected — 要改就改環境變數）。\n\n## 5d. API 中轉站\n\n**管理員設管道**（存 `relay_channels` 表）：`POST /api/admin/relay/channels`，本體：\n\n| 欄位 | 規則 |\n|---|---|\n| `slug` | **選填** 網址代稱（小寫英數與連字號）。留空＝自動從名稱產生（轉不出英數就隨機 `ch-xxxxxx`，撞名自動補尾碼）；**PUT 時留空＝沿用舊代稱**（會員的 /relay 網址不變）。網頁表單 2026-07-14 起已不顯示這欄 |\n| `name` | **必填** 顯示名稱 |\n| `kind` | `openai`（含所有 OpenAI 相容服務與本地 AI）／`anthropic`／`gemini`／`custom`；決定金鑰帶給上游的方式 |\n| `base_url` | **必填** 上游根網址，例 `https://api.openai.com` |\n| `api_key` | 上游金鑰（只有管理員 API 摸得到，回讀一律遮罩） |\n| `models` | **必填** 這個管道可用的模型名稱（陣列，或逗號／換行分隔的字串；限英數與 `. _ / : -`、上限 40 個）。會員頁與 LLM Playground 都靠這份清單 |\n| `system_prompt` | **選填** 這個管道在 **LLM Playground** 的系統提示詞（上限 8000 字，超過回 400、不截斷）。**留空＝套用站台預設**（`PUT /api/admin/settings` 的 `pg_default_system`，沒設過就是程式內建的 `PG_DEFAULT_SYSTEM`；管理員視窗那格的灰字顯示的就是當下實際會套的那段）；填了就**整段取代**預設。要一次改掉全部渠道的人設就改站台預設，不必逐個渠道填。**只作用在 `/playground`**：`/relay` API 中轉是透明代理，一律不注入任何提示詞 — 會員自己送什麼就轉什麼 |\n| `extra_body` | **選填** 合併進 **LLM Playground** 上游請求本體的額外參數，必須是 **JSON 物件字串**（上限 4000 字；存檔當下就驗，不合法回 400）。**留空＝不合併任何東西**（注意：跟 `system_prompt` 的「留空＝套預設」相反，網頁上那格的灰字只是範例）。用來處理各家專屬參數，例 `{\"venice_parameters\":{\"include_venice_system_prompt\":false}}`、OpenAI 的 `reasoning_effort`、Anthropic 的 `thinking`。`model`／`stream`／`messages`／`contents` 擋著**不給覆寫**。**只作用在 `/playground`**，`/relay` 中轉不注入 |\n| `enabled` | 預設 true |\n\n- `GET` → `{ rows }`，每筆含 `models`（陣列）、`has_key`、`key_hint`（金鑰一律遮罩）。\n- `PUT /api/admin/relay/channels/{id}` 整包覆蓋（**`models` 也要帶齊**）；**本體沒帶 `api_key` 欄位＝保留舊金鑰**（帶空字串＝清掉）。`system_prompt` 照整包覆蓋規則走 — **沒帶＝清空**（只有 `api_key` 因為是機密才特別「沒帶＝保留」）。\n- `extra_body` 為什麼需要（2026-07-20 實測）：Venice 這類供應商會在你的系統提示詞**後面**再注入一大段自己的（含 `You are running on Venice.ai` 與模型身分覆寫），排在後面又更具體，直接壓過管道設定的人設 — 要填 `{\"venice_parameters\":{\"include_venice_system_prompt\":false}}` 才關得掉。與其為單一供應商寫死，開成通用欄位。`model` 不給覆寫是刻意的：它經過渠道白名單驗證，能從這裡改等於繞過驗證用沒開放的模型。\n- 預設提示詞定義在 `src/lib/playground.ts` 的 `PG_DEFAULT_SYSTEM`（單一真相來源 — 管道視窗的灰字是 import 過去顯示的，改常數 UI 跟行為一起變）。\n- `system_prompt` 注入到哪：`anthropic` → 請求的 `system` 欄位；`gemini` → `systemInstruction`；`openai`／`custom` → `messages` 最前面補一則 `system`。對話裡原本就有的 `system` 訊息接在管道提示詞**後面**，兩者都生效、不互相覆蓋。提示詞每次請求即時注入，**不會**存進對話紀錄（`pg_messages`），所以改了立刻對舊對話生效。\n- 網頁上新增管道時，選 kind 會自動帶入該家的**官方 Base URL**；用其他供應商（便宜渠道／自架／本地模型）直接改掉即可（你手打過的網址不會被自動蓋掉）。\n- 會員看的 `GET /api/relay/channels` → `{ rows:[{ slug, name, kind, models }], approved }`（approved＝有沒有被批准 relay 服務）；/relay 頁上每個模型名稱都有一鍵複製。\n\n**上游金鑰放哪個標頭：依「路徑」決定，不是只看 kind**（2026-07-12 實測修正）。各家都有兩套介面：\n\n| 上游路徑 | 中轉送出的驗證頭 |\n|---|---|\n| 含 `/openai/` 或結尾是 `chat/completions`（各家的 **OpenAI 相容層**） | `Authorization: Bearer` |\n| Anthropic 原生 `v1/messages` | `x-api-key` |\n| Gemini 原生 `v1beta/models/…` | `x-goog-api-key` |\n| 其他（openai／custom） | `Authorization: Bearer` |\n\n> ⚠️ **Gemini 原生端點不能多送 `Authorization`**：Google 一看到這個標頭就當成 OAuth token，直接回 401「API keys are not supported by this API」。所以是二選一，不能兩個都送。\n\n**會員使用**：把 AI 工具的 Base URL 設成 `https://uaip.cc.cd/relay/{slug}`、API Key 填自己的 `uak-…`：\n\n```\nPOST https://uaip.cc.cd/relay/openai/v1/chat/completions\nAuthorization: Bearer uak-你的金鑰\n→ 伺服器驗身分＋核准狀態 → 換成管理員存的上游金鑰 → 轉發到 https://api.openai.com/v1/chat/completions\n```\n\n- 金鑰放哪都收：`Authorization: Bearer`、`x-api-key`、`x-goog-api-key`、`?key=`（配合各家 SDK）。\n- 路徑照上游原本的填（中轉只換金鑰不改路徑）；回應串流直通。`model` 參數也原樣轉發 — 填管道 `models` 清單裡的名稱即可。\n- 未帶金鑰 401、金鑰無效 401、帳號未被批准 relay 服務 403、管道不存在或停用 404、上游連不上 502。\n- **配額（2026-07-14）**：超過每日額度回 `429 { error:\"quota-exceeded\", hint, used, limit, reset }`、請求太快回 `429 { error:\"rate-limited\", … }`，都帶 `Retry-After` 標頭（秒）。額度＝個人覆寫 → 全域設定 → 內建預設（中轉 500/日、每分鐘 30）；**管理員完全豁免**。今日用量顯示在 /relay 頁與 `GET /api/me` 的 `usage`。\n- **計量**：伺服器順流掃「回應」尾端的 `usage`／`model` 記進 req_log（延遲、token 數；研究數據用）— 只看上游回應、絕不緩衝或解析你送出的內容；會員中斷連線時上游立即取消。\n\n## 5e. VPN 訂閱（多渠道）\n\n跟中轉站同一個模式：管理員到處找便宜機場／自架節點，**每找到一個就加一個渠道**；會員永遠只有一條訂閱網址，伺服器把所有「啟用中」渠道的節點合併給他，**會員看不到渠道存在，也看不到上游網址**。\n\n**管理員設渠道**（存 `vpn_channels` 表）：`POST /api/admin/vpn/channels`，本體：\n\n| 欄位 | 規則 |\n|---|---|\n| `name` | **必填** 顯示名稱（只有管理員看得到，例「某機場 月付3元」） |\n| `kind` | `sub`（機場給的訂閱網址，預設）或 `nodes`（自己貼的節點連結） |\n| `url` | `kind=sub` **必填**：上游訂閱網址（回讀一律遮罩） |\n| `nodes` | `kind=nodes` **必填**：一行一條 `vmess://`／`vless://`／`trojan://`… |\n| `enabled` | 預設 true；false＝暫時不併進會員訂閱（渠道還留著） |\n\n- `PUT /api/admin/vpn/channels/{id}` 整包覆蓋；**本體沒帶 `url` 欄位＝保留舊網址**（帶空字串＝清掉）。\n- `GET /api/admin/vpn/channels` → `{ rows }`，每筆 `id`、`name`、`kind`、`enabled`、`has_url`、`url_hint`（遮罩）、`nodes`、`node_count`。\n\n**會員使用**：`GET /vpn/sub/{token}`（token＝會員的 `vpn_token`，等於通行證，免登入方便 App 定時抓）。把這網址加進 Clash／v2rayN／Shadowrocket 的訂閱即可。未核准／被封鎖 → 403。\n\n伺服器依渠道數自動選最相容的合併方式：\n\n| 啟用中的渠道 | 回給會員的內容 |\n|---|---|\n| 只有 `nodes` 渠道 | 全部手動節點，合併去重 → 標準 base64 訂閱 |\n| 恰好 1 個 `sub` 渠道 | **原樣轉發**（透傳會員 App 的 UA，所以機場回 Clash YAML 也沒問題；流量／到期資訊 Subscription-Userinfo 照傳）。上游若是 base64，手動節點會解碼附加後重新編碼 |\n| 2 個以上 `sub` 渠道 | 各渠道用 v2rayN UA 並行抓取（邊緣快取 5 分鐘）→ 解碼 → 全部節點＋手動節點合併去重 → 一份 base64 訂閱。解不開的（Clash YAML）略過；多渠道時流量資訊無法合併，不回傳 |\n\n> 想同時吃多個機場又要保留流量顯示，就只啟用那一個機場的渠道；其餘用 `enabled:false` 暫存。\n\n## 5f. LLM Playground（/playground）\n\n會員在網頁上直接試用中轉渠道裡的模型（2026-07-13 上線）。可選的模型＝各中轉管道的 `models` 清單；\n上游金鑰全程留在伺服器，會員只帶登入 cookie。對話存 D1、綁帳號、跨裝置同步。\n驗證：登入 cookie（要有 `playground` 服務，**或**管理員開了 `pg_open` 全員開放，見 §5）**或** `Authorization: Bearer <管理金鑰>`（以管理員帳號的身分操作，方便 curl／agent 測試）。\n\n**體驗模式（2026-07-17 v2.0.0，ADR-0009）**：管理員開 `demo_mode`＋設 `demo_channel` 後，**完全未登入**的訪客也能打 `GET /api/playground/models`（只回 demo 那一組、渠道顯示名固定「體驗模式」）與 `POST /api/playground/chat`（SSE 第一筆事件是 `{demo:true}` 而非 `{conv}`）。限制：渠道與模型鎖白名單、輸入整包 4000 字、回覆強制 `demo_max_tokens`、**對話不落資料庫**；fail-closed 限流（每 IP 分鐘/日＋全站日；超額 429 `demo-rate-limited`／`demo-quota-exceeded`，限流器故障 503 `demo-unavailable`）。\n\n- `GET /api/playground/models` → `{ rows:[{ slug, name, models }] }`（只列啟用中且有設模型的渠道；**不含 `kind`** — 那等於標示真實提供商）。\n- `GET /api/playground/conversations` → `{ rows:[{ id, title, channel, model, created_at, updated_at }] }`（自己的，新→舊，最多 100 筆）。**管理員要看全站所有人的對話**看 §5 的 `/api/admin/conversations`（或 /logs 的「總對話紀錄」分頁）。\n- `GET /api/playground/conversations/{id}` → `{ conv, messages:[{ id, role, content, model, created_at }] }`。\n- `PUT /api/playground/conversations/{id}` 本體 `{ \"title\":\"新名字\" }` 改名；`DELETE` 刪除（連同訊息）。\n- `POST /api/playground/chat` 本體：\n\n```json\n{ \"conv_id\": 12, \"channel\": \"gemini\", \"model\": \"gemini-3.1-flash-lite\",\n  \"messages\": [ { \"role\":\"user\", \"content\":\"你好\" } ] }\n```\n\n  - `messages` 是完整上下文（最後一則要是 `user`；`role` 收 user/assistant/system）。\n  - **不帶 `conv_id`＝自動開新對話**（標題取第一句 user 訊息），對話編號由 SSE 第一筆事件回傳。\n  - `model` 一定要在該渠道的 `models` 清單裡，否則 400 `bad-model`。\n  - 回應是 SSE（`text/event-stream`），每筆 `data:` 都是 JSON：`{conv,title?}` →（多筆）`{r:\"思考增量\"}`／`{d:\"增量文字\"}` → `{done:true}`；中途出錯是 `{error,hint}`（已生成的部分照存）。上游一開始就失敗則直接回 JSON 錯誤（會帶 `conv`）。\n  - **`{r:…}` 是推理模型的思考過程**（2026-07-21）：GLM／DeepSeek 系的 `reasoning_content`、OpenRouter 的 `reasoning`、anthropic 的 `thinking_delta`、gemini 標了 `thought` 的 part，一律轉成 `r` 事件。思考內容**不寫進 `pg_messages`**（存的只有正式回覆），重新載入舊對話時不會再出現。非推理模型完全不會有 `r` 事件。\n    > 這個欄位以前被丟掉，導致推理模型在思考期間瀏覽器收不到任何東西 — 畫面空白數十秒像當機，模型若把輸出預算全花在思考上更是「沒回覆、沒報錯」就結束。\n  - **整趟沒有任何正式內容**（`d` 一次都沒來）→ 回 `{error:\"empty-output\", hint}`，不會靜默送 `done`。有收過思考的話 `hint` 會說明是「只輸出思考過程」。此錯誤不含上游身分，**會員看得到全文**。\n  - 中斷連線（前端按「停止」）＝停止生成，已生成的內容照樣存進對話。\n  - 伺服器依渠道 kind 自動轉換請求／串流格式：openai、custom → `/v1/chat/completions`；anthropic → `/v1/messages`；gemini → `/v1beta/models/{model}:streamGenerateContent?alt=sse`。\n  - **錯誤訊息對會員做了消毒**（2026-07-14）：上游的原始錯誤內容（錯誤格式、文件連結、專案編號）會洩漏真實提供商身分，所以會員只看得到安全分類字（401/403→「渠道憑證可能失效」、429→「上游流量限制」、5xx→「上游暫時故障」…），`detail` 原文**只有管理員**（is_admin 或管理金鑰）看得到。\n\n## 6. 常用流程速查\n\n| 想做的事 | 步驟 |\n|---|---|\n| 發文 | （可選）POST media 拿 `/img/{id}` → POST /api/admin/articles（status:published） |\n| 改文 | GET /api/admin/articles/{id} → 改欄位 → **整包** PUT 回去 |\n| 換圖 | POST media 拿**新**編號 → PUT 文章把 cover / 內文網址換成新的（舊編號作廢） |\n| 開新頁面 | POST /api/admin/pages（status:published）→ 上線在 `/p/{slug}` |\n| 頁面掛進選單 | GET /api/menu → items 加 `{ kind:\"link\", label, url:\"/p/{slug}\" }` → PUT /api/admin/menu |\n| 改站名 | PUT /api/admin/settings `{ \"brand\":\"…\" }` |\n| 看流量 | GET /api/logs?limit=50&since=今天零點的UTC時間 |\n| 看全站對話紀錄 | GET /api/admin/conversations（找某人加 `?q=信箱`）→ GET /api/admin/conversations/{id} 讀內容 |\n| 加中轉管道 | POST /api/admin/relay/channels `{ name, kind, base_url, api_key, models:[\"gpt-4o-mini\"] }`（slug 自動產生） |\n| 批准會員（全部服務） | GET /api/admin/users 找 id → PUT /api/admin/users/{id} `{ \"action\":\"approve\" }` |\n| 批准／收回單一服務 | PUT /api/admin/users/{id} `{ \"action\":\"set_services\", \"services\":[\"relay\",\"playground\"] }`（整包覆蓋） |\n| Playground 開放給所有會員 | PUT /api/admin/settings `{ \"pg_open\": true }`（false＝關閉，回到逐人批准） |\n| 加 VPN 渠道 | POST /api/admin/vpn/channels `{ \"name\":\"某機場\", \"kind\":\"sub\", \"url\":\"https://…\" }` |\n| 暫停某渠道 | GET /api/admin/vpn/channels 找 id → PUT `{ name, kind, enabled:false }`（會員訂閱立刻少掉那些節點） |\n\n轉貼別站新聞的原則：**用自己的話改寫＋文末附資料來源連結**，不要整篇照抄。\n這些操作在網頁上也都能做：**管理員設定 /settings**（站名、聯絡連結、Playground 與體驗模式、配額、計量開關、模型定價、自訂頁面）、文章後台 /admin、☰ 側邊欄（選單編輯 — 打開選單按「選單」旁的 ✎）、成員管理 /members、訪客紀錄 /logs、中轉站 /relay、VPN /vpn。\n\n## 7. 錯誤回應\n\n出錯時回 `{ \"error\": \"代碼\", \"hint\": \"中文提示（可能沒有）\", \"detail\": \"技術細節（可能沒有）\" }`：\n\n| HTTP 狀態 | 常見 error | 說明 |\n|---|---|---|\n| 400 | bad-input / bad-id / bad-slug / bad-url / too-many / empty / bad-action / self / bad-model | 參數或本體不合規則（看 hint）；bad-model＝模型不在渠道清單裡 |\n| 401 | unauthorized / no-key / bad-key / no-admin-user | 金鑰沒帶或不對（中轉：會員金鑰無效） |\n| 403 | bad-origin / not-approved / blocked / protected | 跨站被擋／該服務未被批准或帳號被封鎖／受保護的管理員帳號 |\n| 404 | not-found / unknown-channel | 內容不存在（或公開 API 查到的是草稿）／中轉管道不存在 |\n| 409 | slug-taken | 自訂頁面或管道的 slug 已被使用 |\n| 429 | quota-exceeded / rate-limited | 超過每日額度／請求太快（中轉與 Playground；帶 `Retry-After` 標頭與 `used`/`limit`/`reset` 欄位；管理員豁免） |\n| 502 | upstream-unreachable / upstream-error / no-upstream-key | 中轉／VPN／Playground 上游連不上或回錯；渠道沒設上游金鑰 |\n| 413 | too-large | 圖片超過 1.8MB |\n| 415 | bad-type | 圖片格式不是 webp / jpeg / png / gif |\n| 500 | no-db / query-failed / insert-failed / update-failed / delete-failed / save-failed | 伺服器或資料庫問題（看 detail） |\n";
// 已渲染＋已消毒的 HTML — /api-docs 直接吐出，執行期不再跑 marked／sanitize。
export const APIDOC_HTML: string = "<p>網頁後台能做的每一件事，這裡都有對應的 HTTP API — 用 curl、排程或 AI agent 都能操作整個網站。</p>\n<h2>1. 開始之前</h2>\n<table>\n<thead>\n<tr>\n<th>項目</th>\n<th>值</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>正式站</td>\n<td><code>https://uaip.cc.cd</code>（Cloudflare Workers）</td>\n</tr>\n<tr>\n<td>本機開發</td>\n<td><code>http://localhost:8787</code>（<code>npx wrangler dev</code>）</td>\n</tr>\n<tr>\n<td>回應格式</td>\n<td>一律 JSON（UTF-8）</td>\n</tr>\n<tr>\n<td>時間欄位</td>\n<td>一律 UTC 的 ISO 8601（例 <code>2026-07-09T03:00:00.000Z</code>），顯示時自行轉時區</td>\n</tr>\n</tbody></table>\n<p><strong>三種身分</strong>：</p>\n<ol>\n<li><strong>公開</strong>：免驗證（whoami、已發佈內容、選單、站名）。</li>\n<li><strong>管理員</strong>：路徑含 <code>/admin</code> 的、以及 <code>/api/logs</code>。兩種通過方式（擇一）：<ul>\n<li>請求標頭 <code>Authorization: Bearer &lt;管理金鑰&gt;</code>（curl／排程／AI agent 用）。管理金鑰＝Cloudflare Workers secret <strong>LOGS_TOKEN</strong>，跟 /logs、/admin 網頁登入同一把；值記在 ADMIN.md（不會上網）。</li>\n<li>管理員 Google 帳號的登入 cookie（瀏覽器用）：管理員信箱登入後，管理頁與管理員 API 免金鑰。管理員信箱＝環境變數 <strong>ADMIN_EMAILS</strong>（逗號分隔，例 <code>admin@example.com</code>；沒設定＝沒有信箱直升管理員，只認資料庫 users.is_admin）。</li>\n<li><strong>本機開發（localhost）免金鑰</strong>；正式站沒帶或帶錯一律回 401。用 cookie 身分時，跨網站送出的請求會被 Origin 檢查擋掉（防 CSRF）。</li>\n<li>換金鑰：<code>printf &#39;新金鑰&#39; | npx wrangler secret put LOGS_TOKEN</code>，設定後立即生效（Workers secret 不需重新部署）。</li>\n</ul>\n</li>\n<li><strong>會員</strong>：任何人用 Google 登入即為會員（見 <code>/auth/login</code>）。會員功能（API 中轉、VPN 訂閱）要<strong>管理員核准</strong>（status=approved）後才生效。<ul>\n<li>網頁操作靠登入 cookie；<strong>API 中轉</strong>另用會員自己的金鑰 <code>uak-…</code>（在 /relay 頁產生，帶法同各家 AI API）。</li>\n</ul>\n</li>\n</ol>\n<h3>30 秒上手：發一篇新聞</h3>\n<pre><code class=\"language-bat\">:: 1) 文章存成「UTF-8 編碼」的 art.json（中文寫在指令列會變亂碼，一定要走檔案）：\n::    { &quot;category&quot;:&quot;news&quot;, &quot;status&quot;:&quot;published&quot;, &quot;title&quot;:&quot;標題&quot;,\n::      &quot;summary&quot;:&quot;一兩句摘要&quot;, &quot;cover&quot;:&quot;/img/5&quot;, &quot;body_md&quot;:&quot;內文 **Markdown**&quot; }\n:: 2) 送出（Windows cmd 換行符是 ^；Linux/macOS 改用 \\）：\ncurl -X POST https://uaip.cc.cd/api/admin/articles ^\n  -H &quot;Authorization: Bearer 管理金鑰&quot; ^\n  -H &quot;content-type: application/json; charset=utf-8&quot; ^\n  --data-binary @art.json\n</code></pre>\n<p>回 <code>{ &quot;id&quot;: 12, &quot;status&quot;: &quot;published&quot; }</code> → 文章立即上線在 <code>/news/12</code>。</p>\n<h2>2. 端點總覽</h2>\n<h3>公開（免金鑰）</h3>\n<table>\n<thead>\n<tr>\n<th>方法與路徑</th>\n<th>用途</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><code>GET /api/whoami</code></td>\n<td>訪客自己的連線資訊（IP、UA、地理位置）</td>\n</tr>\n<tr>\n<td><code>GET /api/articles</code></td>\n<td>已發佈文章列表（分頁、可篩分類）</td>\n</tr>\n<tr>\n<td><code>GET /api/articles/{id}</code></td>\n<td>單篇已發佈文章（含 Markdown 原稿）</td>\n</tr>\n<tr>\n<td><code>GET /api/pages</code></td>\n<td>已發佈自訂頁面列表</td>\n</tr>\n<tr>\n<td><code>GET /api/pages/{slug}</code></td>\n<td>單一已發佈自訂頁面</td>\n</tr>\n<tr>\n<td><code>GET /api/menu</code></td>\n<td>側邊欄選單</td>\n</tr>\n<tr>\n<td><code>GET /api/settings</code></td>\n<td>網站公開設定（站名、Playground 是否全員開放、聯絡連結）</td>\n</tr>\n<tr>\n<td><code>GET /api/health</code></td>\n<td>健康檢查 <code>{ ok, version, db }</code>（部署後 smoke 測試用）</td>\n</tr>\n<tr>\n<td><code>POST /api/csp-report</code></td>\n<td>CSP 違規回報收集端（瀏覽器自動送；10% 取樣進錯誤日誌；永遠 204）</td>\n</tr>\n<tr>\n<td><code>GET /img/{id}</code></td>\n<td>圖片（D1 讀出、邊緣快取一年）</td>\n</tr>\n<tr>\n<td><code>GET /feed</code></td>\n<td>RSS 訂閱源（最新 20 篇）</td>\n</tr>\n<tr>\n<td><code>GET /sitemap</code></td>\n<td>搜尋引擎網址清單（含文章與自訂頁面）</td>\n</tr>\n</tbody></table>\n<h3>會員（要登入 cookie）</h3>\n<table>\n<thead>\n<tr>\n<th>方法與路徑</th>\n<th>用途</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><code>GET /api/me</code></td>\n<td>我是誰（登入狀態、被批准的服務清單 <code>services</code>、是否管理員；未登入回 <code>{user:null}</code>）</td>\n</tr>\n<tr>\n<td><code>POST /api/account/key</code></td>\n<td>產生／重生自己的中轉金鑰 <code>uak-…</code>（明文只回一次）</td>\n</tr>\n<tr>\n<td><code>DELETE /api/account/key</code></td>\n<td>撤銷自己的中轉金鑰</td>\n</tr>\n<tr>\n<td><code>POST /api/account/vpn-token</code></td>\n<td>重生自己的 VPN 訂閱代碼（舊訂閱網址立即失效）</td>\n</tr>\n<tr>\n<td><code>GET /api/relay/channels</code></td>\n<td>目前可用的中轉管道清單（含各管道的模型名稱 <code>models</code>；不含金鑰）</td>\n</tr>\n<tr>\n<td><code>GET /api/playground/models</code></td>\n<td>Playground 可選的模型清單（依渠道分組；要有 playground 服務）</td>\n</tr>\n<tr>\n<td><code>POST /api/playground/chat</code></td>\n<td>Playground 聊天（SSE 串流；要有 playground 服務，見 §5f）</td>\n</tr>\n<tr>\n<td><code>GET /api/playground/conversations</code></td>\n<td>自己的 Playground 對話列表</td>\n</tr>\n<tr>\n<td><code>GET/PUT/DELETE /api/playground/conversations/{id}</code></td>\n<td>讀取訊息／改名／刪除自己的對話</td>\n</tr>\n</tbody></table>\n<h3>會員服務端點（不同驗證）</h3>\n<table>\n<thead>\n<tr>\n<th>方法與路徑</th>\n<th>驗證</th>\n<th>用途</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><code>ANY /relay/{管道}/{上游路徑…}</code></td>\n<td>會員金鑰 <code>uak-…</code></td>\n<td>API 中轉：轉發到上游、串流直通（見 §6）</td>\n</tr>\n<tr>\n<td><code>GET /vpn/sub/{token}</code></td>\n<td>訂閱 token 本身</td>\n<td>VPN 訂閱鏡像：給 Clash／v2rayN 直接訂閱（見 §7）</td>\n</tr>\n<tr>\n<td><code>GET /auth/login?next=…</code></td>\n<td>—</td>\n<td>導向 Google 登入（localhost 提供測試登入表單）</td>\n</tr>\n<tr>\n<td><code>POST /auth/logout</code></td>\n<td>登入 cookie</td>\n<td>登出</td>\n</tr>\n</tbody></table>\n<h3>管理員（要金鑰）</h3>\n<table>\n<thead>\n<tr>\n<th>方法與路徑</th>\n<th>用途</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><code>GET /api/admin/articles</code></td>\n<td>全部文章（<strong>含草稿</strong>，依更新時間排序，最多 500 筆）</td>\n</tr>\n<tr>\n<td><code>POST /api/admin/articles</code></td>\n<td>新增文章</td>\n</tr>\n<tr>\n<td><code>GET /api/admin/articles/{id}</code></td>\n<td>讀單篇（含草稿、含原稿）</td>\n</tr>\n<tr>\n<td><code>PUT /api/admin/articles/{id}</code></td>\n<td>更新文章（<strong>整包覆蓋</strong>）</td>\n</tr>\n<tr>\n<td><code>DELETE /api/admin/articles/{id}</code></td>\n<td>刪除文章（不可復原）</td>\n</tr>\n<tr>\n<td><code>GET /api/admin/pages</code></td>\n<td>全部自訂頁面（<strong>含草稿</strong>）</td>\n</tr>\n<tr>\n<td><code>POST /api/admin/pages</code></td>\n<td><strong>新增自訂頁面（開新連結就靠這支）</strong></td>\n</tr>\n<tr>\n<td><code>GET /api/admin/pages/{id或slug}</code></td>\n<td>讀單頁（含草稿、含原稿）</td>\n</tr>\n<tr>\n<td><code>PUT /api/admin/pages/{id或slug}</code></td>\n<td>更新頁面（<strong>整包覆蓋</strong>，可改 slug）</td>\n</tr>\n<tr>\n<td><code>DELETE /api/admin/pages/{id或slug}</code></td>\n<td>刪除頁面（不可復原）</td>\n</tr>\n<tr>\n<td><code>POST /api/admin/media</code></td>\n<td>上傳圖片</td>\n</tr>\n<tr>\n<td><code>PUT /api/admin/menu</code></td>\n<td>覆蓋側邊欄選單</td>\n</tr>\n<tr>\n<td><code>GET /api/admin/settings</code></td>\n<td>目前存的網站設定原況（給 /settings 管理頁當編輯初值；數字鍵沒設過回 <code>null</code>，另附 <code>defaults</code>）</td>\n</tr>\n<tr>\n<td><code>PUT /api/admin/settings</code></td>\n<td>改網站設定（站名、Playground 全員開放、配額全域預設、計量開關）</td>\n</tr>\n<tr>\n<td><code>GET /api/logs</code></td>\n<td>訪客紀錄查詢</td>\n</tr>\n<tr>\n<td><code>GET /api/admin/errors</code></td>\n<td>站內錯誤日誌（<code>?limit&amp;offset&amp;src</code>；relay/playground/OAuth/CSP 埋點）</td>\n</tr>\n<tr>\n<td><code>DELETE /api/admin/errors</code></td>\n<td>清空錯誤日誌</td>\n</tr>\n<tr>\n<td><code>GET /api/admin/stats</code></td>\n<td>用量統計（<code>?days=7</code>；每日×服務、渠道×模型、每人彙總、原始耗時值供算 p95、估算成本）— /logs 用量分頁的數據源</td>\n</tr>\n<tr>\n<td><code>GET /api/admin/conversations</code></td>\n<td>全站 Playground 對話總表（<code>?limit&amp;offset&amp;q&amp;user_id</code>；新→舊，帶會員信箱）— /logs 總對話紀錄分頁的數據源</td>\n</tr>\n<tr>\n<td><code>GET /api/admin/conversations/{id}</code></td>\n<td>讀任一會員的單則對話（含全部訊息）</td>\n</tr>\n<tr>\n<td><code>GET /api/admin/prices</code></td>\n<td>模型定價表（成本記帳用）</td>\n</tr>\n<tr>\n<td><code>PUT /api/admin/prices</code></td>\n<td>覆蓋模型定價表（<strong>整包覆蓋</strong>；pattern 尾端 <code>*</code>＝前綴匹配）</td>\n</tr>\n<tr>\n<td><code>GET /api/admin/apidoc</code></td>\n<td>這份文件的 Markdown 原稿（<code>{ md }</code>）</td>\n</tr>\n<tr>\n<td><code>GET /api/admin/users</code></td>\n<td>全部會員（狀態、已批准服務、用量、最後登入）</td>\n</tr>\n<tr>\n<td><code>PUT /api/admin/users/{id}</code></td>\n<td>批准／封鎖／升降管理員／分服務批准（<code>{ action }</code>，見 §5c）</td>\n</tr>\n<tr>\n<td><code>DELETE /api/admin/users/{id}</code></td>\n<td>刪除會員</td>\n</tr>\n<tr>\n<td><code>GET /api/admin/relay/channels</code></td>\n<td>全部中轉管道（上游金鑰遮罩）</td>\n</tr>\n<tr>\n<td><code>POST /api/admin/relay/channels</code></td>\n<td>新增中轉管道</td>\n</tr>\n<tr>\n<td><code>PUT /api/admin/relay/channels/{id}</code></td>\n<td>更新管道（整包覆蓋；沒帶 api_key＝保留舊金鑰）</td>\n</tr>\n<tr>\n<td><code>DELETE /api/admin/relay/channels/{id}</code></td>\n<td>刪除管道</td>\n</tr>\n<tr>\n<td><code>GET /api/admin/vpn/channels</code></td>\n<td>全部 VPN 渠道（上游訂閱網址遮罩）</td>\n</tr>\n<tr>\n<td><code>POST /api/admin/vpn/channels</code></td>\n<td>新增 VPN 渠道（機場訂閱或手動節點）</td>\n</tr>\n<tr>\n<td><code>PUT /api/admin/vpn/channels/{id}</code></td>\n<td>更新渠道（整包覆蓋；沒帶 url＝保留舊網址）</td>\n</tr>\n<tr>\n<td><code>DELETE /api/admin/vpn/channels/{id}</code></td>\n<td>刪除渠道</td>\n</tr>\n</tbody></table>\n<h2>3. 三條鐵則（先讀這個再動手）</h2>\n<ol>\n<li><strong>PUT 是整包覆蓋</strong>（文章、頁面、選單都是）：先 GET 拿舊資料 → 改要改的欄位 → 整包 PUT 回去。沒帶的欄位會被清空。</li>\n<li><strong>圖片編號永遠不能重複使用</strong>：<code>/img/{id}</code> 掛一年 immutable 邊緣快取，而 uaip.cc.cd 的快取清除權在 cc.cd 網域主手上、我們清不掉。刪過的編號作廢；換圖＝上傳拿新編號＋更新文章裡的網址。也<strong>不要</strong>重設 media 表的流水號。</li>\n<li><strong>中文內容一定走 UTF-8 檔案</strong>：curl 用 <code>--data-binary @檔案</code> 傳送；把中文直接寫在 Windows 指令列會變亂碼（實測踩過）。</li>\n</ol>\n<h2>4. 公開 API 詳細</h2>\n<h3>GET /api/whoami</h3>\n<p>回傳由 Cloudflare 邊緣節點觀測到的請求資訊。欄位：<code>ip</code>、<code>ua</code>、<code>lang</code>、<code>country</code>、<code>city</code>、<code>region</code>、<code>region_code</code>、<code>postal</code>、<code>latitude</code>、<code>longitude</code>、<code>timezone</code>、<code>asn</code>、<code>isp</code>、<code>colo</code>、<code>http</code>、<code>tls</code>。</p>\n<h3>GET /api/articles — 已發佈文章列表</h3>\n<table>\n<thead>\n<tr>\n<th>參數</th>\n<th>說明</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><code>category</code></td>\n<td><code>news</code> 或 <code>article</code>；省略＝全部</td>\n</tr>\n<tr>\n<td><code>p</code></td>\n<td>頁碼，預設 1</td>\n</tr>\n<tr>\n<td><code>per</code></td>\n<td>每頁筆數 1–50，預設 10</td>\n</tr>\n</tbody></table>\n<p>回 <code>{ rows, total, page, per, pages }</code>；rows 每筆含 <code>id</code>、<code>category</code>、<code>title</code>、<code>summary</code>、<code>cover</code>、<code>views</code>、<code>published_at</code>，依發佈時間新到舊。草稿一律看不到；用 API 讀<strong>不會</strong>增加瀏覽數（views 只算真人看文章頁）。</p>\n<h3>GET /api/articles/{id} — 單篇已發佈文章</h3>\n<p>回 <code>{ row }</code>，含 <code>body_md</code>（Markdown 原稿）。加 <strong><code>?html=1</code></strong> 多回 <code>body_html</code>（伺服器轉好的 HTML，跟正式文章頁同設定）。找不到或還是草稿 → 404。</p>\n<h3>GET /api/pages — 已發佈自訂頁面列表</h3>\n<p>回 <code>{ rows }</code>，每筆含 <code>slug</code>、<code>title</code>、<code>summary</code>、<code>updated_at</code>。每頁的公開網址＝ <strong><code>/p/{slug}</code></strong>（例 slug=about → <code>https://uaip.cc.cd/p/about</code>）。</p>\n<h3>GET /api/pages/{slug} — 單一已發佈自訂頁面</h3>\n<p>回 <code>{ row }</code>，含 <code>body_md</code>。加 <strong><code>?html=1</code></strong> 多回 <code>body_html</code>。找不到或還是草稿 → 404。</p>\n<h3>GET /api/menu — 側邊欄選單</h3>\n<p>回 <code>{ items, custom }</code>。items 是「由上到下」的平面陣列，每項：</p>\n<table>\n<thead>\n<tr>\n<th>欄位</th>\n<th>說明</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><code>kind</code></td>\n<td><code>section</code>（分類標題）或 <code>link</code>（連結）</td>\n</tr>\n<tr>\n<td><code>label</code></td>\n<td>中文名稱</td>\n</tr>\n<tr>\n<td><code>label_en</code></td>\n<td>英文名稱（空字串＝英文介面也顯示中文）</td>\n</tr>\n<tr>\n<td><code>url</code></td>\n<td>連結網址（section 為空字串）</td>\n</tr>\n</tbody></table>\n<p><code>custom:false</code> 表示還沒自訂過，回的是內建預設選單。</p>\n<h3>GET /api/settings — 網站公開設定</h3>\n<p>回 <code>{ brand, custom, pg_open, contact_url, demo }</code>。brand＝站名（用在分頁標題、og:site_name、JSON-LD、RSS 頻道名）；<code>custom:false</code> 表示用內建預設（＝正式網址主機名）。<code>pg_open</code>＝Playground 是否對所有登入會員開放（見 §5 的網站設定）。<code>contact_url</code>＝管理員聯絡連結（會員頁登入閘門的「聯絡我」鈕；空字串＝沒設定、前端不顯示該鈕）。<code>demo</code>＝Playground 體驗模式是否開放匿名試聊（布林；渠道與額度細節不公開）。</p>\n<h2>5. 管理員 API 詳細</h2>\n<h3>文章：/api/admin/articles</h3>\n<p>POST（新增）與 PUT（更新）共用同一組 JSON 欄位：</p>\n<table>\n<thead>\n<tr>\n<th>欄位</th>\n<th>規則</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><code>category</code></td>\n<td><code>news</code>（新聞）或 <code>article</code>（文章）；預設 news</td>\n</tr>\n<tr>\n<td><code>status</code></td>\n<td><code>draft</code>（草稿）或 <code>published</code>（發佈）；預設 draft</td>\n</tr>\n<tr>\n<td><code>title</code></td>\n<td><strong>必填</strong>，最長 200 字</td>\n</tr>\n<tr>\n<td><code>summary</code></td>\n<td>最長 500 字 — 列表兩行摘要，也是搜尋結果與分享卡描述</td>\n</tr>\n<tr>\n<td><code>cover</code></td>\n<td>縮圖網址，最長 300 字（通常是 <code>/img/{id}</code>，也可貼外部網址）</td>\n</tr>\n<tr>\n<td><code>body_md</code></td>\n<td>內文 Markdown，最長 200KB（空一行分段、<code>## 小標</code>、<code>**粗體**</code>、<code>[文字](網址)</code>、插圖 <code>![說明](/img/{id})</code>；breaks 模式：按一次 Enter 就是換行）</td>\n</tr>\n</tbody></table>\n<ul>\n<li>POST 回 <code>{ id, status }</code>；PUT 回 <code>{ id, status }</code>；DELETE 回 <code>{ ok:true }</code>。</li>\n<li><code>published_at</code> 在<strong>第一次發佈</strong>時寫入，之後再編輯、轉草稿再發佈都不變（列表排序穩定）。</li>\n<li>文章上線網址：<code>/news/{id}</code> 或 <code>/articles/{id}</code>（依 category）。</li>\n</ul>\n<h3>自訂頁面：/api/admin/pages — 用 API 開新連結</h3>\n<p>新增一個頁面＝網站多一個公開網址 <strong><code>/p/{slug}</code></strong>。適合「關於本站」「隱私權政策」「聯絡方式」這類獨立頁。</p>\n<p>POST 與 PUT 共用欄位：</p>\n<table>\n<thead>\n<tr>\n<th>欄位</th>\n<th>規則</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><code>slug</code></td>\n<td><strong>必填</strong> — 網址代稱：小寫英數與連字號（頭尾不能是連字號），最長 64 字。例 <code>about</code>、<code>privacy-policy</code></td>\n</tr>\n<tr>\n<td><code>title</code></td>\n<td><strong>必填</strong>，最長 200 字（頁面大標＋分頁標題）</td>\n</tr>\n<tr>\n<td><code>status</code></td>\n<td><code>draft</code>（草稿）或 <code>published</code>（發佈）；預設 draft。<strong>草稿對外看不到</strong></td>\n</tr>\n<tr>\n<td><code>summary</code></td>\n<td>最長 500 字 — meta description（SEO 與分享卡描述）</td>\n</tr>\n<tr>\n<td><code>body_md</code></td>\n<td>內文 Markdown，最長 200KB（規則同文章）</td>\n</tr>\n</tbody></table>\n<ul>\n<li>POST 回 <code>{ id, slug, status, url }</code>；slug 已被用回 <strong>409 <code>{ error:&quot;slug-taken&quot; }</code></strong>。</li>\n<li>單頁路由 <code>/{id或slug}</code>：純數字當編號、其他當 slug，兩種都可以（agent 用 slug 比較直覺）。</li>\n<li>PUT 可以改 slug（頁面搬新網址，舊網址會變 404 — 已被收錄或被連結的頁面不建議改）。</li>\n<li>發佈後自動進 <code>/sitemap</code>；<strong>不會</strong>自動出現在側邊欄 — 要掛選單就再 <code>PUT /api/admin/menu</code> 加一條 url 為 <code>/p/{slug}</code> 的連結（見下）。</li>\n</ul>\n<p>建立並發佈一個「關於本站」頁：</p>\n<pre><code class=\"language-bat\">:: page.json（UTF-8）：\n::   { &quot;slug&quot;:&quot;about&quot;, &quot;status&quot;:&quot;published&quot;, &quot;title&quot;:&quot;關於本站&quot;,\n::     &quot;summary&quot;:&quot;這個網站是誰、在做什麼。&quot;, &quot;body_md&quot;:&quot;## 哈囉\\n\\n這裡是……&quot; }\ncurl -X POST https://uaip.cc.cd/api/admin/pages ^\n  -H &quot;Authorization: Bearer 管理金鑰&quot; ^\n  -H &quot;content-type: application/json; charset=utf-8&quot; --data-binary @page.json\n:: 回 { &quot;id&quot;:1, &quot;slug&quot;:&quot;about&quot;, &quot;status&quot;:&quot;published&quot;, &quot;url&quot;:&quot;/p/about&quot; }\n</code></pre>\n<h3>圖片：POST /api/admin/media</h3>\n<ul>\n<li>請求本體＝圖片<strong>二進位</strong>（不是表單、不是 base64），Content-Type 帶 <code>image/webp</code>、<code>image/jpeg</code>、<code>image/png</code> 或 <code>image/gif</code>。</li>\n<li>大小上限 <strong>1.8MB</strong>（D1 單值限 2MB）。走 API 上傳<strong>不會自動壓縮</strong>，請先自己縮好（建議最寬 1400–1600px、JPEG 品質 85 左右）；網頁後台上傳才有自動壓縮。</li>\n<li>可選參數 <code>?w=寬&amp;h=高</code>（記尺寸，後台顯示用）。</li>\n<li>回 <code>{ id, url, bytes, w, h }</code>，url 形如 <code>/img/9</code> — 填進文章 cover，或以 <code>![說明](/img/9)</code> 插進內文。</li>\n</ul>\n<pre><code class=\"language-bat\">curl -X POST &quot;https://uaip.cc.cd/api/admin/media?w=1400&amp;h=788&quot; ^\n  -H &quot;Authorization: Bearer 管理金鑰&quot; ^\n  -H &quot;content-type: image/jpeg&quot; --data-binary @cover.jpg\n</code></pre>\n<h3>選單：PUT /api/admin/menu</h3>\n<p>本體 <code>{ &quot;items&quot;: [ … ] }</code>，格式同 GET /api/menu 的 items；整份選單照陣列順序<strong>覆蓋</strong>寫入。</p>\n<ul>\n<li>每項規則：<code>label</code> 必填最長 60 字；<code>label_en</code> 選填最長 60 字；link 的 <code>url</code> 必填最長 300 字，<strong>必須以 <code>/</code> 或 <code>http://</code> 或 <code>https://</code> 開頭</strong>；最多 60 項。</li>\n<li>傳 <strong><code>{ &quot;items&quot;: [] }</code>（空陣列）＝清掉自訂選單＝還原內建預設</strong>。</li>\n<li>回 <code>{ ok, count, custom }</code>。</li>\n<li>側邊欄的「管理員區」（管理員設定、訪客紀錄、API 文件）不在選單資料裡 — 那是登入過的裝置由前端動態長出來的，改不到也不用管。</li>\n</ul>\n<p>標準流程（先拿現況、改完整包放回）：</p>\n<pre><code class=\"language-bat\">curl https://uaip.cc.cd/api/menu &gt; menu.json\n:: 編輯 menu.json，例如 items 尾端加 { &quot;kind&quot;:&quot;link&quot;, &quot;label&quot;:&quot;關於本站&quot;,\n::   &quot;label_en&quot;:&quot;About&quot;, &quot;url&quot;:&quot;/p/about&quot; }，然後：\ncurl -X PUT https://uaip.cc.cd/api/admin/menu ^\n  -H &quot;Authorization: Bearer 管理金鑰&quot; ^\n  -H &quot;content-type: application/json; charset=utf-8&quot; --data-binary @menu.json\n</code></pre>\n<h3>網站設定：GET / PUT /api/admin/settings</h3>\n<p><strong>GET</strong>（2026-07-17，/settings 管理頁的數據源）回目前<strong>存的</strong>原況：<code>{ ok, brand, custom, contact_url, pg_open, pg_default_system, relay_meter, quota_relay_day, quota_pg_day, rl_per_min, demo_mode, demo_active, demo_channel, demo_models, demo_per_min, demo_per_ip_day, demo_global_day, demo_max_tokens, tg_chat_id, tg_token_set, tg_token_hint, tg_env_set, tg_active, defaults }</code> — 數字鍵沒設過回 <code>null</code>（不是內建預設值），內建預設放在 <code>defaults</code> 物件；<code>demo_mode</code> 是開關本身的儲存值、<code>demo_active</code> 才是真正生效與否（開關＋<code>demo_channel</code> 都要有）；Telegram bot token <strong>絕不回明文</strong>（只回 <code>tg_token_set</code> 與尾 4 碼 <code>tg_token_hint</code>）。</p>\n<p><strong>PUT：本體帶哪個鍵就改哪個鍵，沒帶的不動</strong>（2026-07-14 起；跟文章／選單的整包覆蓋不同）。回 <code>{ ok, brand, custom, contact_url, pg_open, pg_default_system, quota_relay_day, quota_pg_day, rl_per_min, relay_meter, demo_* }</code>（改完的現況；配額鍵沒設過時顯示內建預設）。</p>\n<table>\n<thead>\n<tr>\n<th>鍵</th>\n<th>說明</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><code>brand</code></td>\n<td>站名，最長 60 字；<strong>傳空字串＝還原內建預設</strong>（＝正式網址主機名）。改完立即生效（分頁標題、og:site_name、JSON-LD、RSS 頻道名；主站首頁的「IP·UA 查詢」標題不受影響）</td>\n</tr>\n<tr>\n<td><code>contact_url</code></td>\n<td>管理員對外聯絡連結（<code>http(s)://</code> 開頭，最長 300 字）；顯示在會員頁登入閘門的「聯絡我」鈕。<strong>空字串＝移除＝不顯示聯絡鈕</strong></td>\n</tr>\n<tr>\n<td><code>pg_open</code></td>\n<td><code>true</code>／<code>false</code> — <strong>Playground 開放給所有登入會員</strong>：開啟後任何登入會員不用逐一批准就能用 LLM Playground（被封鎖的帳號照樣擋；只影響 playground，relay 與 vpn 照舊看個人批准）。<code>false</code>＝回到逐人批准。網頁上在 /members 頁最上方也有這顆開關</td>\n</tr>\n<tr>\n<td><code>pg_default_system</code></td>\n<td><strong>Playground 的預設系統提示詞</strong>（2026-07-21；最長 4000 字，超過截斷）：所有<strong>沒有自己填</strong> <code>system_prompt</code> 的渠道共用這一段 — 改一次等於一次換掉全部渠道，不必逐個開視窗。渠道自己填了就以渠道為準（不疊加）。<strong>空字串＝刪鍵＝還原程式內建的 <code>PG_DEFAULT_SYSTEM</code></strong>；GET 的 <code>defaults.pg_default_system</code> 就是那段內建值（網頁上拿它當灰字）。<strong>只作用在 <code>/playground</code></strong>，<code>/relay</code> 中轉照樣不注入任何東西。網頁在 /settings 的「Playground 預設系統提示詞」卡</td>\n</tr>\n<tr>\n<td><code>quota_relay_day</code></td>\n<td>中轉每日請求數的<strong>全域預設</strong>（正整數）；<code>null</code> ＝ 回到內建預設 500。個人覆寫（§5c 的 <code>set_quota</code>）優先於這個值；<strong>管理員完全不吃配額</strong></td>\n</tr>\n<tr>\n<td><code>quota_pg_day</code></td>\n<td>Playground 每日訊息數的全域預設；<code>null</code> ＝ 內建預設 200</td>\n</tr>\n<tr>\n<td><code>rl_per_min</code></td>\n<td>每分鐘請求數上限（滾動 60 秒、中轉＋Playground 合併計）；<code>null</code> ＝ 內建預設 30</td>\n</tr>\n<tr>\n<td><code>relay_meter</code></td>\n<td><code>false</code> ＝ 中轉退回<strong>純直通</strong>（不掃 usage、不寫 req_log）— 計量出怪問題時的免部署保險；<code>true</code> ＝ 恢復計量（預設）。平常不要動</td>\n</tr>\n<tr>\n<td><code>tg_bot_token</code></td>\n<td>Telegram 告警的 bot token（2026-07-17 起可存這裡；最長 100 字，<strong>空字串＝刪鍵</strong>）。cron 每 5 分鐘掃 errlog 推播時<strong>這裡優先</strong>、Cloudflare secrets（TG_BOT_TOKEN）後備。回讀一律遮罩（<code>tg_token_set</code>／<code>tg_token_hint</code>）、audit 不落明文。網頁在 /settings 的「Telegram 告警」卡</td>\n</tr>\n<tr>\n<td><code>tg_chat_id</code></td>\n<td>Telegram 告警的 chat id（最長 50 字，空字串＝刪鍵；同樣 D1 優先、secrets TG_CHAT_ID 後備）。token 與 chat id <strong>都設好</strong>告警才會發送</td>\n</tr>\n<tr>\n<td><code>demo_mode</code></td>\n<td><code>true</code>／<code>false</code> — <strong>Playground 體驗模式</strong>（2026-07-17 v2.0.0）：開啟後<strong>未登入訪客</strong>可直接在 /playground 試聊。要同時設好 <code>demo_channel</code> 才生效。fail-closed 限流（詳見 ADR-0009）：每 IP 每分鐘／每日＋全站每日三道上限，限流器故障時直接 503 絕不放行</td>\n</tr>\n<tr>\n<td><code>demo_channel</code></td>\n<td>體驗模式鎖定的渠道 slug（<strong>必設</strong>，沒設＝demo 不生效）；訪客只能用這個渠道</td>\n</tr>\n<tr>\n<td><code>demo_models</code></td>\n<td>體驗模式的模型白名單（逗號分隔）；空＝該渠道全部模型</td>\n</tr>\n<tr>\n<td><code>demo_per_min</code></td>\n<td>體驗模式每 IP 每分鐘上限；<code>null</code>＝內建預設 3</td>\n</tr>\n<tr>\n<td><code>demo_per_ip_day</code></td>\n<td>每 IP 每日上限；<code>null</code>＝內建預設 10</td>\n</tr>\n<tr>\n<td><code>demo_global_day</code></td>\n<td><strong>全站</strong>每日上限（燒錢保險）；<code>null</code>＝內建預設 200</td>\n</tr>\n<tr>\n<td><code>demo_max_tokens</code></td>\n<td>強制的回覆 token 上限；<code>null</code>＝內建預設 512</td>\n</tr>\n</tbody></table>\n<pre><code class=\"language-bat\">curl -X PUT https://uaip.cc.cd/api/admin/settings ^\n  -H &quot;Authorization: Bearer 管理金鑰&quot; ^\n  -H &quot;content-type: application/json&quot; --data-binary &quot;{\\&quot;brand\\&quot;:\\&quot;新站名\\&quot;}&quot;\n\n:: Playground 開放給所有登入會員（false＝關閉）：\ncurl -X PUT https://uaip.cc.cd/api/admin/settings ^\n  -H &quot;Authorization: Bearer 管理金鑰&quot; ^\n  -H &quot;content-type: application/json&quot; --data-binary &quot;{\\&quot;pg_open\\&quot;:true}&quot;\n</code></pre>\n<h3>模型定價（成本記帳）：/api/admin/prices</h3>\n<p>成本記帳（2026-07-17 v2.0.0）：req_log 早就記了每次請求的 token 數，這張定價表讓 stats 與 /logs 用量分頁能把 token 換算成<strong>估算</strong>美元成本。定價只影響報告顯示，不影響配額（配額算次數，見 §網站設定）。</p>\n<ul>\n<li><code>GET</code> → <code>{ items: [ { pattern, input_usd_per_m, output_usd_per_m, note, updated_at }, … ] }</code></li>\n<li><code>PUT</code> 本體 <code>{ items: [ … ] }</code>，<strong>整包覆蓋</strong>（跟選單同款：先 GET → 改 → 整包 PUT；空陣列＝清空）。</li>\n</ul>\n<table>\n<thead>\n<tr>\n<th>欄位</th>\n<th>說明</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><code>pattern</code></td>\n<td>模型名稱；尾端 <code>*</code> ＝前綴匹配（例 <code>gpt-4o*</code>）。<strong>精確名優先於前綴、前綴取最長</strong>（<code>gpt-4o-mini*</code> 贏過 <code>gpt-4o*</code>）</td>\n</tr>\n<tr>\n<td><code>input_usd_per_m</code></td>\n<td>每百萬 input tokens 的美元價（≥0）</td>\n</tr>\n<tr>\n<td><code>output_usd_per_m</code></td>\n<td>每百萬 output tokens 的美元價（≥0）</td>\n</tr>\n<tr>\n<td><code>note</code></td>\n<td>備註（例：官網牌價日期），最長 200 字</td>\n</tr>\n</tbody></table>\n<pre><code class=\"language-bat\">curl -X PUT https://uaip.cc.cd/api/admin/prices ^\n  -H &quot;Authorization: Bearer 管理金鑰&quot; ^\n  -H &quot;content-type: application/json&quot; ^\n  --data-binary &quot;{\\&quot;items\\&quot;:[{\\&quot;pattern\\&quot;:\\&quot;gpt-4o*\\&quot;,\\&quot;input_usd_per_m\\&quot;:2.5,\\&quot;output_usd_per_m\\&quot;:10}]}&quot;\n</code></pre>\n<p>沒對上定價的模型在 stats 回應的 <code>unpriced_models</code> 陣列與 /logs 用量分頁會被點名提醒。</p>\n<h3>訪客紀錄：GET /api/logs</h3>\n<table>\n<thead>\n<tr>\n<th>參數</th>\n<th>說明</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><code>limit</code></td>\n<td>1–200，預設 50</td>\n</tr>\n<tr>\n<td><code>offset</code></td>\n<td>分頁位移</td>\n</tr>\n<tr>\n<td><code>q</code></td>\n<td>模糊搜尋（ip / ua / path / country / city / isp）</td>\n</tr>\n<tr>\n<td><code>since</code></td>\n<td>ISO 時間 — 額外回傳該時間之後的瀏覽數與不重複 IP 數（today / todayIps）</td>\n</tr>\n</tbody></table>\n<p>回 <code>{ rows, total, today?, todayIps? }</code>。</p>\n<h3>總對話紀錄：/api/admin/conversations</h3>\n<p>管理視角看<strong>全站會員</strong>在 Playground 存下的對話（2026-07-20 上線）——會員版 <code>/api/playground/conversations</code> 只看得到自己的，這兩支不限擁有者。網頁在 <strong>/logs 的「總對話紀錄」分頁</strong>。</p>\n<p><code>GET /api/admin/conversations</code></p>\n<table>\n<thead>\n<tr>\n<th>參數</th>\n<th>說明</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><code>limit</code></td>\n<td>1–200，預設 50</td>\n</tr>\n<tr>\n<td><code>offset</code></td>\n<td>分頁位移</td>\n</tr>\n<tr>\n<td><code>q</code></td>\n<td>模糊搜尋（標題／會員信箱／姓名／模型／渠道；<strong>不搜訊息內容</strong>）。網頁上沒有這個欄位，只給 curl／agent 用</td>\n</tr>\n<tr>\n<td><code>user_id</code></td>\n<td>只看某個會員的對話</td>\n</tr>\n</tbody></table>\n<p>回 <code>{ rows, total }</code>，<code>rows</code> 依 <code>updated_at</code> <strong>新→舊</strong>；每列：<code>id</code>、<code>user_id</code>、<code>email</code>、<code>name</code>（對話是誰的）、<code>title</code>、<code>channel</code>、<code>model</code>、<code>msgs</code>（訊息則數）、<code>created_at</code>、<code>updated_at</code>。帳號已刪除時 <code>email</code>／<code>name</code> 是 <code>null</code>。</p>\n<p><code>GET /api/admin/conversations/{id}</code> → <code>{ conv, messages }</code>：<code>conv</code> 是那列（額外帶 <code>email</code>、<code>name</code>），<code>messages</code> 依時間<strong>舊→新</strong>（聊天的閱讀順序）、上限 500 則，每則 <code>id</code>、<code>role</code>、<code>content</code>、<code>model</code>、<code>created_at</code>。找不到回 404。</p>\n<blockquote>\n<p>這兩支<strong>唯讀</strong>——管理員這邊不提供刪除，避免誤刪會員資料；會員自己可以在 /playground 刪自己的對話。\n體驗模式（未登入試用）的對話<strong>不落資料庫</strong>，所以不會出現在這裡。</p>\n</blockquote>\n<h2>5b. 會員與帳號 API</h2>\n<ul>\n<li><code>GET /api/me</code> → <code>{ user }</code>（未登入 <code>{ user:null }</code>）。user 含 <code>email</code>、<code>name</code>、<code>picture</code>、<code>status</code>（pending/approved/blocked）、<code>is_admin</code>、<code>approved</code>、<code>services</code>（被批准的服務陣列，如 <code>[&quot;relay&quot;,&quot;vpn&quot;,&quot;playground&quot;]</code>；管理員固定是全部）、<code>has_key</code>、<code>key_hint</code>、<code>key_at</code>、<code>relay_calls</code>、<code>usage</code>（2026-07-14 起：今日用量 <code>{ relay_today, relay_limit, pg_today, pg_limit }</code> — 只含有權限的服務、管理員 limit 是 <code>null</code>＝無上限、兩服務都沒權限時整塊省略；UTC 午夜重置）。<strong><code>vpn_token</code>／<code>vpn_pulls</code> 只有「管理員或被批准 vpn 服務」的人才有</strong>（VPN 隱形：無權限者連鍵都不出現，<code>/vpn</code> 頁對他們也回 SPA、選單也不渲染）。</li>\n<li><code>POST /api/account/key</code> → <code>{ key, key_hint, key_at }</code>。<strong>key 明文只在這次回應出現</strong>，資料庫只存 SHA-256；重生會讓舊金鑰立即失效。<code>DELETE</code> 撤銷。</li>\n<li><code>POST /api/account/vpn-token</code> → <code>{ vpn_token }</code>。重生訂閱代碼（舊 <code>/vpn/sub/&lt;舊token&gt;</code> 立即失效）。</li>\n<li><code>POST /api/account/logout-all</code>（2026-07-14）→ <code>{ ok }</code>。<strong>登出所有裝置</strong>：刪光自己全部 session（含這一把）並清本機 cookie。手機不見／公用電腦忘了登出時用；頭像下拉選單也有這個鈕。</li>\n<li>以上都要登入 cookie；跨站請求被 Origin 擋（403 bad-origin）。</li>\n</ul>\n<h2>5c. 成員管理：/api/admin/users（分服務批准）</h2>\n<p>2026-07-13 起改<strong>分服務批准</strong>：三個服務 <code>relay</code>（API 中轉站）、<code>vpn</code>、<code>playground</code>（LLM Playground）可以分別開關，存在 <code>users.services</code>（逗號分隔）。管理員帳號不看清單、全部服務都能用。</p>\n<blockquote>\n<p><code>playground</code> 另有<strong>全站開關</strong>（<code>PUT /api/admin/settings</code> 的 <code>pg_open</code>，見 §5）：開啟時所有登入會員都能用 Playground、不看個人批准（<code>/api/me</code> 的 <code>services</code> 也會多出 playground）；關閉才回到這裡的逐人批准。relay 與 vpn 沒有全站開關。</p>\n</blockquote>\n<ul>\n<li><code>GET</code> → <code>{ rows }</code>：每筆 <code>id</code>、<code>email</code>、<code>name</code>、<code>picture</code>、<code>status</code>、<code>services</code>（逗號分隔字串）、<code>is_admin</code>、<code>relay_calls</code>、<code>vpn_pulls</code>、<code>last_login</code>、<code>created_at</code>、配額覆寫欄（<code>quota_relay_day</code>、<code>quota_pg_day</code>、<code>rl_per_min</code>；<code>null</code>＝用全域）、今日用量（<code>relay_today</code>、<code>pg_today</code>，UTC 日窗）；排序 pending 在前。</li>\n<li><code>PUT /api/admin/users/{id}</code> 本體三選一：<ul>\n<li><code>{ &quot;action&quot;: &quot;approve&quot; | &quot;block&quot; | &quot;unblock&quot; | &quot;make_admin&quot; | &quot;drop_admin&quot; }</code> — <code>approve</code> 是快速鍵＝<strong>一次批准全部服務</strong>；<code>unblock</code> 恢復原本的服務清單（清單是空的就退回 pending）。封鎖會同時把該會員踢下線（刪其 session）。</li>\n<li><code>{ &quot;action&quot;: &quot;set_services&quot;, &quot;services&quot;: [&quot;relay&quot;,&quot;vpn&quot;] }</code> — <strong>整包覆蓋</strong>服務清單（只收合法服務名）。給了任何服務＝status 變 approved；全部收回＝退回 pending；封鎖中的帳號只改清單、狀態不動。</li>\n<li><code>{ &quot;action&quot;: &quot;set_quota&quot;, &quot;quota_relay_day&quot;: 100, &quot;quota_pg_day&quot;: null, &quot;rl_per_min&quot;: 10 }</code> — <strong>個人配額覆寫</strong>（2026-07-14）：帶哪鍵改哪鍵；值收 0 以上整數（0＝直接關掉該服務的額度）或 <code>null</code>＝清掉覆寫、回到全域預設（§5 的網站設定）。管理員帳號不吃配額，設了也沒作用。網頁上在 /members 每個會員的「配額」鈕（有自訂會多顯示 <code>*</code>）</li>\n<li><code>{ &quot;action&quot;: &quot;revoke_sessions&quot; }</code> —（2026-07-14）撤銷該會員<strong>所有裝置</strong>的登入狀態（session 全刪；帳號狀態與服務不動）。懷疑帳號被冒用時先用這個。</li>\n</ul>\n</li>\n<li>所有變更（users／settings／channels／menu／articles／pages／media）都會寫 <strong>audit_log</strong>（誰、何時、對誰、做了什麼；summary 絕不含金鑰或上游網址本體）。</li>\n<li><code>DELETE /api/admin/users/{id}</code> 刪除帳號。</li>\n<li><strong>護欄</strong>：不能封鎖／降級／刪除自己；也不能動到 ADMIN_EMAILS 指定的管理員帳號（回 403 protected — 要改就改環境變數）。</li>\n</ul>\n<h2>5d. API 中轉站</h2>\n<p><strong>管理員設管道</strong>（存 <code>relay_channels</code> 表）：<code>POST /api/admin/relay/channels</code>，本體：</p>\n<table>\n<thead>\n<tr>\n<th>欄位</th>\n<th>規則</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><code>slug</code></td>\n<td><strong>選填</strong> 網址代稱（小寫英數與連字號）。留空＝自動從名稱產生（轉不出英數就隨機 <code>ch-xxxxxx</code>，撞名自動補尾碼）；<strong>PUT 時留空＝沿用舊代稱</strong>（會員的 /relay 網址不變）。網頁表單 2026-07-14 起已不顯示這欄</td>\n</tr>\n<tr>\n<td><code>name</code></td>\n<td><strong>必填</strong> 顯示名稱</td>\n</tr>\n<tr>\n<td><code>kind</code></td>\n<td><code>openai</code>（含所有 OpenAI 相容服務與本地 AI）／<code>anthropic</code>／<code>gemini</code>／<code>custom</code>；決定金鑰帶給上游的方式</td>\n</tr>\n<tr>\n<td><code>base_url</code></td>\n<td><strong>必填</strong> 上游根網址，例 <code>https://api.openai.com</code></td>\n</tr>\n<tr>\n<td><code>api_key</code></td>\n<td>上游金鑰（只有管理員 API 摸得到，回讀一律遮罩）</td>\n</tr>\n<tr>\n<td><code>models</code></td>\n<td><strong>必填</strong> 這個管道可用的模型名稱（陣列，或逗號／換行分隔的字串；限英數與 <code>. _ / : -</code>、上限 40 個）。會員頁與 LLM Playground 都靠這份清單</td>\n</tr>\n<tr>\n<td><code>system_prompt</code></td>\n<td><strong>選填</strong> 這個管道在 <strong>LLM Playground</strong> 的系統提示詞（上限 8000 字，超過回 400、不截斷）。<strong>留空＝套用站台預設</strong>（<code>PUT /api/admin/settings</code> 的 <code>pg_default_system</code>，沒設過就是程式內建的 <code>PG_DEFAULT_SYSTEM</code>；管理員視窗那格的灰字顯示的就是當下實際會套的那段）；填了就<strong>整段取代</strong>預設。要一次改掉全部渠道的人設就改站台預設，不必逐個渠道填。<strong>只作用在 <code>/playground</code></strong>：<code>/relay</code> API 中轉是透明代理，一律不注入任何提示詞 — 會員自己送什麼就轉什麼</td>\n</tr>\n<tr>\n<td><code>extra_body</code></td>\n<td><strong>選填</strong> 合併進 <strong>LLM Playground</strong> 上游請求本體的額外參數，必須是 <strong>JSON 物件字串</strong>（上限 4000 字；存檔當下就驗，不合法回 400）。<strong>留空＝不合併任何東西</strong>（注意：跟 <code>system_prompt</code> 的「留空＝套預設」相反，網頁上那格的灰字只是範例）。用來處理各家專屬參數，例 <code>{&quot;venice_parameters&quot;:{&quot;include_venice_system_prompt&quot;:false}}</code>、OpenAI 的 <code>reasoning_effort</code>、Anthropic 的 <code>thinking</code>。<code>model</code>／<code>stream</code>／<code>messages</code>／<code>contents</code> 擋著<strong>不給覆寫</strong>。<strong>只作用在 <code>/playground</code></strong>，<code>/relay</code> 中轉不注入</td>\n</tr>\n<tr>\n<td><code>enabled</code></td>\n<td>預設 true</td>\n</tr>\n</tbody></table>\n<ul>\n<li><code>GET</code> → <code>{ rows }</code>，每筆含 <code>models</code>（陣列）、<code>has_key</code>、<code>key_hint</code>（金鑰一律遮罩）。</li>\n<li><code>PUT /api/admin/relay/channels/{id}</code> 整包覆蓋（<strong><code>models</code> 也要帶齊</strong>）；<strong>本體沒帶 <code>api_key</code> 欄位＝保留舊金鑰</strong>（帶空字串＝清掉）。<code>system_prompt</code> 照整包覆蓋規則走 — <strong>沒帶＝清空</strong>（只有 <code>api_key</code> 因為是機密才特別「沒帶＝保留」）。</li>\n<li><code>extra_body</code> 為什麼需要（2026-07-20 實測）：Venice 這類供應商會在你的系統提示詞<strong>後面</strong>再注入一大段自己的（含 <code>You are running on Venice.ai</code> 與模型身分覆寫），排在後面又更具體，直接壓過管道設定的人設 — 要填 <code>{&quot;venice_parameters&quot;:{&quot;include_venice_system_prompt&quot;:false}}</code> 才關得掉。與其為單一供應商寫死，開成通用欄位。<code>model</code> 不給覆寫是刻意的：它經過渠道白名單驗證，能從這裡改等於繞過驗證用沒開放的模型。</li>\n<li>預設提示詞定義在 <code>src/lib/playground.ts</code> 的 <code>PG_DEFAULT_SYSTEM</code>（單一真相來源 — 管道視窗的灰字是 import 過去顯示的，改常數 UI 跟行為一起變）。</li>\n<li><code>system_prompt</code> 注入到哪：<code>anthropic</code> → 請求的 <code>system</code> 欄位；<code>gemini</code> → <code>systemInstruction</code>；<code>openai</code>／<code>custom</code> → <code>messages</code> 最前面補一則 <code>system</code>。對話裡原本就有的 <code>system</code> 訊息接在管道提示詞<strong>後面</strong>，兩者都生效、不互相覆蓋。提示詞每次請求即時注入，<strong>不會</strong>存進對話紀錄（<code>pg_messages</code>），所以改了立刻對舊對話生效。</li>\n<li>網頁上新增管道時，選 kind 會自動帶入該家的<strong>官方 Base URL</strong>；用其他供應商（便宜渠道／自架／本地模型）直接改掉即可（你手打過的網址不會被自動蓋掉）。</li>\n<li>會員看的 <code>GET /api/relay/channels</code> → <code>{ rows:[{ slug, name, kind, models }], approved }</code>（approved＝有沒有被批准 relay 服務）；/relay 頁上每個模型名稱都有一鍵複製。</li>\n</ul>\n<p><strong>上游金鑰放哪個標頭：依「路徑」決定，不是只看 kind</strong>（2026-07-12 實測修正）。各家都有兩套介面：</p>\n<table>\n<thead>\n<tr>\n<th>上游路徑</th>\n<th>中轉送出的驗證頭</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>含 <code>/openai/</code> 或結尾是 <code>chat/completions</code>（各家的 <strong>OpenAI 相容層</strong>）</td>\n<td><code>Authorization: Bearer</code></td>\n</tr>\n<tr>\n<td>Anthropic 原生 <code>v1/messages</code></td>\n<td><code>x-api-key</code></td>\n</tr>\n<tr>\n<td>Gemini 原生 <code>v1beta/models/…</code></td>\n<td><code>x-goog-api-key</code></td>\n</tr>\n<tr>\n<td>其他（openai／custom）</td>\n<td><code>Authorization: Bearer</code></td>\n</tr>\n</tbody></table>\n<blockquote>\n<p>⚠️ <strong>Gemini 原生端點不能多送 <code>Authorization</code></strong>：Google 一看到這個標頭就當成 OAuth token，直接回 401「API keys are not supported by this API」。所以是二選一，不能兩個都送。</p>\n</blockquote>\n<p><strong>會員使用</strong>：把 AI 工具的 Base URL 設成 <code>https://uaip.cc.cd/relay/{slug}</code>、API Key 填自己的 <code>uak-…</code>：</p>\n<pre><code>POST https://uaip.cc.cd/relay/openai/v1/chat/completions\nAuthorization: Bearer uak-你的金鑰\n→ 伺服器驗身分＋核准狀態 → 換成管理員存的上游金鑰 → 轉發到 https://api.openai.com/v1/chat/completions\n</code></pre>\n<ul>\n<li>金鑰放哪都收：<code>Authorization: Bearer</code>、<code>x-api-key</code>、<code>x-goog-api-key</code>、<code>?key=</code>（配合各家 SDK）。</li>\n<li>路徑照上游原本的填（中轉只換金鑰不改路徑）；回應串流直通。<code>model</code> 參數也原樣轉發 — 填管道 <code>models</code> 清單裡的名稱即可。</li>\n<li>未帶金鑰 401、金鑰無效 401、帳號未被批准 relay 服務 403、管道不存在或停用 404、上游連不上 502。</li>\n<li><strong>配額（2026-07-14）</strong>：超過每日額度回 <code>429 { error:&quot;quota-exceeded&quot;, hint, used, limit, reset }</code>、請求太快回 <code>429 { error:&quot;rate-limited&quot;, … }</code>，都帶 <code>Retry-After</code> 標頭（秒）。額度＝個人覆寫 → 全域設定 → 內建預設（中轉 500/日、每分鐘 30）；<strong>管理員完全豁免</strong>。今日用量顯示在 /relay 頁與 <code>GET /api/me</code> 的 <code>usage</code>。</li>\n<li><strong>計量</strong>：伺服器順流掃「回應」尾端的 <code>usage</code>／<code>model</code> 記進 req_log（延遲、token 數；研究數據用）— 只看上游回應、絕不緩衝或解析你送出的內容；會員中斷連線時上游立即取消。</li>\n</ul>\n<h2>5e. VPN 訂閱（多渠道）</h2>\n<p>跟中轉站同一個模式：管理員到處找便宜機場／自架節點，<strong>每找到一個就加一個渠道</strong>；會員永遠只有一條訂閱網址，伺服器把所有「啟用中」渠道的節點合併給他，<strong>會員看不到渠道存在，也看不到上游網址</strong>。</p>\n<p><strong>管理員設渠道</strong>（存 <code>vpn_channels</code> 表）：<code>POST /api/admin/vpn/channels</code>，本體：</p>\n<table>\n<thead>\n<tr>\n<th>欄位</th>\n<th>規則</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><code>name</code></td>\n<td><strong>必填</strong> 顯示名稱（只有管理員看得到，例「某機場 月付3元」）</td>\n</tr>\n<tr>\n<td><code>kind</code></td>\n<td><code>sub</code>（機場給的訂閱網址，預設）或 <code>nodes</code>（自己貼的節點連結）</td>\n</tr>\n<tr>\n<td><code>url</code></td>\n<td><code>kind=sub</code> <strong>必填</strong>：上游訂閱網址（回讀一律遮罩）</td>\n</tr>\n<tr>\n<td><code>nodes</code></td>\n<td><code>kind=nodes</code> <strong>必填</strong>：一行一條 <code>vmess://</code>／<code>vless://</code>／<code>trojan://</code>…</td>\n</tr>\n<tr>\n<td><code>enabled</code></td>\n<td>預設 true；false＝暫時不併進會員訂閱（渠道還留著）</td>\n</tr>\n</tbody></table>\n<ul>\n<li><code>PUT /api/admin/vpn/channels/{id}</code> 整包覆蓋；<strong>本體沒帶 <code>url</code> 欄位＝保留舊網址</strong>（帶空字串＝清掉）。</li>\n<li><code>GET /api/admin/vpn/channels</code> → <code>{ rows }</code>，每筆 <code>id</code>、<code>name</code>、<code>kind</code>、<code>enabled</code>、<code>has_url</code>、<code>url_hint</code>（遮罩）、<code>nodes</code>、<code>node_count</code>。</li>\n</ul>\n<p><strong>會員使用</strong>：<code>GET /vpn/sub/{token}</code>（token＝會員的 <code>vpn_token</code>，等於通行證，免登入方便 App 定時抓）。把這網址加進 Clash／v2rayN／Shadowrocket 的訂閱即可。未核准／被封鎖 → 403。</p>\n<p>伺服器依渠道數自動選最相容的合併方式：</p>\n<table>\n<thead>\n<tr>\n<th>啟用中的渠道</th>\n<th>回給會員的內容</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>只有 <code>nodes</code> 渠道</td>\n<td>全部手動節點，合併去重 → 標準 base64 訂閱</td>\n</tr>\n<tr>\n<td>恰好 1 個 <code>sub</code> 渠道</td>\n<td><strong>原樣轉發</strong>（透傳會員 App 的 UA，所以機場回 Clash YAML 也沒問題；流量／到期資訊 Subscription-Userinfo 照傳）。上游若是 base64，手動節點會解碼附加後重新編碼</td>\n</tr>\n<tr>\n<td>2 個以上 <code>sub</code> 渠道</td>\n<td>各渠道用 v2rayN UA 並行抓取（邊緣快取 5 分鐘）→ 解碼 → 全部節點＋手動節點合併去重 → 一份 base64 訂閱。解不開的（Clash YAML）略過；多渠道時流量資訊無法合併，不回傳</td>\n</tr>\n</tbody></table>\n<blockquote>\n<p>想同時吃多個機場又要保留流量顯示，就只啟用那一個機場的渠道；其餘用 <code>enabled:false</code> 暫存。</p>\n</blockquote>\n<h2>5f. LLM Playground（/playground）</h2>\n<p>會員在網頁上直接試用中轉渠道裡的模型（2026-07-13 上線）。可選的模型＝各中轉管道的 <code>models</code> 清單；\n上游金鑰全程留在伺服器，會員只帶登入 cookie。對話存 D1、綁帳號、跨裝置同步。\n驗證：登入 cookie（要有 <code>playground</code> 服務，<strong>或</strong>管理員開了 <code>pg_open</code> 全員開放，見 §5）<strong>或</strong> <code>Authorization: Bearer &lt;管理金鑰&gt;</code>（以管理員帳號的身分操作，方便 curl／agent 測試）。</p>\n<p><strong>體驗模式（2026-07-17 v2.0.0，ADR-0009）</strong>：管理員開 <code>demo_mode</code>＋設 <code>demo_channel</code> 後，<strong>完全未登入</strong>的訪客也能打 <code>GET /api/playground/models</code>（只回 demo 那一組、渠道顯示名固定「體驗模式」）與 <code>POST /api/playground/chat</code>（SSE 第一筆事件是 <code>{demo:true}</code> 而非 <code>{conv}</code>）。限制：渠道與模型鎖白名單、輸入整包 4000 字、回覆強制 <code>demo_max_tokens</code>、<strong>對話不落資料庫</strong>；fail-closed 限流（每 IP 分鐘/日＋全站日；超額 429 <code>demo-rate-limited</code>／<code>demo-quota-exceeded</code>，限流器故障 503 <code>demo-unavailable</code>）。</p>\n<ul>\n<li><code>GET /api/playground/models</code> → <code>{ rows:[{ slug, name, models }] }</code>（只列啟用中且有設模型的渠道；<strong>不含 <code>kind</code></strong> — 那等於標示真實提供商）。</li>\n<li><code>GET /api/playground/conversations</code> → <code>{ rows:[{ id, title, channel, model, created_at, updated_at }] }</code>（自己的，新→舊，最多 100 筆）。<strong>管理員要看全站所有人的對話</strong>看 §5 的 <code>/api/admin/conversations</code>（或 /logs 的「總對話紀錄」分頁）。</li>\n<li><code>GET /api/playground/conversations/{id}</code> → <code>{ conv, messages:[{ id, role, content, model, created_at }] }</code>。</li>\n<li><code>PUT /api/playground/conversations/{id}</code> 本體 <code>{ &quot;title&quot;:&quot;新名字&quot; }</code> 改名；<code>DELETE</code> 刪除（連同訊息）。</li>\n<li><code>POST /api/playground/chat</code> 本體：</li>\n</ul>\n<pre><code class=\"language-json\">{ &quot;conv_id&quot;: 12, &quot;channel&quot;: &quot;gemini&quot;, &quot;model&quot;: &quot;gemini-3.1-flash-lite&quot;,\n  &quot;messages&quot;: [ { &quot;role&quot;:&quot;user&quot;, &quot;content&quot;:&quot;你好&quot; } ] }\n</code></pre>\n<ul>\n<li><code>messages</code> 是完整上下文（最後一則要是 <code>user</code>；<code>role</code> 收 user/assistant/system）。</li>\n<li><strong>不帶 <code>conv_id</code>＝自動開新對話</strong>（標題取第一句 user 訊息），對話編號由 SSE 第一筆事件回傳。</li>\n<li><code>model</code> 一定要在該渠道的 <code>models</code> 清單裡，否則 400 <code>bad-model</code>。</li>\n<li>回應是 SSE（<code>text/event-stream</code>），每筆 <code>data:</code> 都是 JSON：<code>{conv,title?}</code> →（多筆）<code>{r:&quot;思考增量&quot;}</code>／<code>{d:&quot;增量文字&quot;}</code> → <code>{done:true}</code>；中途出錯是 <code>{error,hint}</code>（已生成的部分照存）。上游一開始就失敗則直接回 JSON 錯誤（會帶 <code>conv</code>）。</li>\n<li><strong><code>{r:…}</code> 是推理模型的思考過程</strong>（2026-07-21）：GLM／DeepSeek 系的 <code>reasoning_content</code>、OpenRouter 的 <code>reasoning</code>、anthropic 的 <code>thinking_delta</code>、gemini 標了 <code>thought</code> 的 part，一律轉成 <code>r</code> 事件。思考內容<strong>不寫進 <code>pg_messages</code></strong>（存的只有正式回覆），重新載入舊對話時不會再出現。非推理模型完全不會有 <code>r</code> 事件。<blockquote>\n<p>這個欄位以前被丟掉，導致推理模型在思考期間瀏覽器收不到任何東西 — 畫面空白數十秒像當機，模型若把輸出預算全花在思考上更是「沒回覆、沒報錯」就結束。</p>\n</blockquote>\n</li>\n<li><strong>整趟沒有任何正式內容</strong>（<code>d</code> 一次都沒來）→ 回 <code>{error:&quot;empty-output&quot;, hint}</code>，不會靜默送 <code>done</code>。有收過思考的話 <code>hint</code> 會說明是「只輸出思考過程」。此錯誤不含上游身分，<strong>會員看得到全文</strong>。</li>\n<li>中斷連線（前端按「停止」）＝停止生成，已生成的內容照樣存進對話。</li>\n<li>伺服器依渠道 kind 自動轉換請求／串流格式：openai、custom → <code>/v1/chat/completions</code>；anthropic → <code>/v1/messages</code>；gemini → <code>/v1beta/models/{model}:streamGenerateContent?alt=sse</code>。</li>\n<li><strong>錯誤訊息對會員做了消毒</strong>（2026-07-14）：上游的原始錯誤內容（錯誤格式、文件連結、專案編號）會洩漏真實提供商身分，所以會員只看得到安全分類字（401/403→「渠道憑證可能失效」、429→「上游流量限制」、5xx→「上游暫時故障」…），<code>detail</code> 原文<strong>只有管理員</strong>（is_admin 或管理金鑰）看得到。</li>\n</ul>\n<h2>6. 常用流程速查</h2>\n<table>\n<thead>\n<tr>\n<th>想做的事</th>\n<th>步驟</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>發文</td>\n<td>（可選）POST media 拿 <code>/img/{id}</code> → POST /api/admin/articles（status:published）</td>\n</tr>\n<tr>\n<td>改文</td>\n<td>GET /api/admin/articles/{id} → 改欄位 → <strong>整包</strong> PUT 回去</td>\n</tr>\n<tr>\n<td>換圖</td>\n<td>POST media 拿<strong>新</strong>編號 → PUT 文章把 cover / 內文網址換成新的（舊編號作廢）</td>\n</tr>\n<tr>\n<td>開新頁面</td>\n<td>POST /api/admin/pages（status:published）→ 上線在 <code>/p/{slug}</code></td>\n</tr>\n<tr>\n<td>頁面掛進選單</td>\n<td>GET /api/menu → items 加 <code>{ kind:&quot;link&quot;, label, url:&quot;/p/{slug}&quot; }</code> → PUT /api/admin/menu</td>\n</tr>\n<tr>\n<td>改站名</td>\n<td>PUT /api/admin/settings <code>{ &quot;brand&quot;:&quot;…&quot; }</code></td>\n</tr>\n<tr>\n<td>看流量</td>\n<td>GET /api/logs?limit=50&amp;since=今天零點的UTC時間</td>\n</tr>\n<tr>\n<td>看全站對話紀錄</td>\n<td>GET /api/admin/conversations（找某人加 <code>?q=信箱</code>）→ GET /api/admin/conversations/{id} 讀內容</td>\n</tr>\n<tr>\n<td>加中轉管道</td>\n<td>POST /api/admin/relay/channels <code>{ name, kind, base_url, api_key, models:[&quot;gpt-4o-mini&quot;] }</code>（slug 自動產生）</td>\n</tr>\n<tr>\n<td>批准會員（全部服務）</td>\n<td>GET /api/admin/users 找 id → PUT /api/admin/users/{id} <code>{ &quot;action&quot;:&quot;approve&quot; }</code></td>\n</tr>\n<tr>\n<td>批准／收回單一服務</td>\n<td>PUT /api/admin/users/{id} <code>{ &quot;action&quot;:&quot;set_services&quot;, &quot;services&quot;:[&quot;relay&quot;,&quot;playground&quot;] }</code>（整包覆蓋）</td>\n</tr>\n<tr>\n<td>Playground 開放給所有會員</td>\n<td>PUT /api/admin/settings <code>{ &quot;pg_open&quot;: true }</code>（false＝關閉，回到逐人批准）</td>\n</tr>\n<tr>\n<td>加 VPN 渠道</td>\n<td>POST /api/admin/vpn/channels <code>{ &quot;name&quot;:&quot;某機場&quot;, &quot;kind&quot;:&quot;sub&quot;, &quot;url&quot;:&quot;https://…&quot; }</code></td>\n</tr>\n<tr>\n<td>暫停某渠道</td>\n<td>GET /api/admin/vpn/channels 找 id → PUT <code>{ name, kind, enabled:false }</code>（會員訂閱立刻少掉那些節點）</td>\n</tr>\n</tbody></table>\n<p>轉貼別站新聞的原則：<strong>用自己的話改寫＋文末附資料來源連結</strong>，不要整篇照抄。\n這些操作在網頁上也都能做：<strong>管理員設定 /settings</strong>（站名、聯絡連結、Playground 與體驗模式、配額、計量開關、模型定價、自訂頁面）、文章後台 /admin、☰ 側邊欄（選單編輯 — 打開選單按「選單」旁的 ✎）、成員管理 /members、訪客紀錄 /logs、中轉站 /relay、VPN /vpn。</p>\n<h2>7. 錯誤回應</h2>\n<p>出錯時回 <code>{ &quot;error&quot;: &quot;代碼&quot;, &quot;hint&quot;: &quot;中文提示（可能沒有）&quot;, &quot;detail&quot;: &quot;技術細節（可能沒有）&quot; }</code>：</p>\n<table>\n<thead>\n<tr>\n<th>HTTP 狀態</th>\n<th>常見 error</th>\n<th>說明</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>400</td>\n<td>bad-input / bad-id / bad-slug / bad-url / too-many / empty / bad-action / self / bad-model</td>\n<td>參數或本體不合規則（看 hint）；bad-model＝模型不在渠道清單裡</td>\n</tr>\n<tr>\n<td>401</td>\n<td>unauthorized / no-key / bad-key / no-admin-user</td>\n<td>金鑰沒帶或不對（中轉：會員金鑰無效）</td>\n</tr>\n<tr>\n<td>403</td>\n<td>bad-origin / not-approved / blocked / protected</td>\n<td>跨站被擋／該服務未被批准或帳號被封鎖／受保護的管理員帳號</td>\n</tr>\n<tr>\n<td>404</td>\n<td>not-found / unknown-channel</td>\n<td>內容不存在（或公開 API 查到的是草稿）／中轉管道不存在</td>\n</tr>\n<tr>\n<td>409</td>\n<td>slug-taken</td>\n<td>自訂頁面或管道的 slug 已被使用</td>\n</tr>\n<tr>\n<td>429</td>\n<td>quota-exceeded / rate-limited</td>\n<td>超過每日額度／請求太快（中轉與 Playground；帶 <code>Retry-After</code> 標頭與 <code>used</code>/<code>limit</code>/<code>reset</code> 欄位；管理員豁免）</td>\n</tr>\n<tr>\n<td>502</td>\n<td>upstream-unreachable / upstream-error / no-upstream-key</td>\n<td>中轉／VPN／Playground 上游連不上或回錯；渠道沒設上游金鑰</td>\n</tr>\n<tr>\n<td>413</td>\n<td>too-large</td>\n<td>圖片超過 1.8MB</td>\n</tr>\n<tr>\n<td>415</td>\n<td>bad-type</td>\n<td>圖片格式不是 webp / jpeg / png / gif</td>\n</tr>\n<tr>\n<td>500</td>\n<td>no-db / query-failed / insert-failed / update-failed / delete-failed / save-failed</td>\n<td>伺服器或資料庫問題（看 detail）</td>\n</tr>\n</tbody></table>\n";
